patterns.code:
function createVoiceInput(options) {
  const opts = options || {};
  const lang = opts.lang || 'en-US';
  let listening = false;

  function isSupported() {
    return typeof window !== 'undefined' &&
      !!(window.SpeechRecognition || window.webkitSpeechRecognition);
  }

  function start(onResult, onError) {
    if (!isSupported() || listening) return false;
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    const recognition = new SR();
    recognition.continuous = false;
    recognition.interimResults = false;
    recognition.lang = lang;
    recognition.onresult = function(e) {
      listening = false;
      if (onResult) onResult(e.results[0][0].transcript);
    };
    recognition.onerror = function(e) { listening = false; if (onError) onError(e.error); };
    recognition.onend = function() { listening = false; };
    recognition.start();
    listening = true;
    return true;
  }

  function stop() { listening = false; }
  function isListening() { return listening; }

  return { isSupported, start, stop, isListening };
}

patterns.testCode:
const { describe, it } = require('node:test');
const assert = require('node:assert/strict');

describe('createVoiceInput', function() {
  it('returns an object with the correct methods', function() {
    const vi = createVoiceInput();
    assert.equal(typeof vi.isSupported, 'function');
    assert.equal(typeof vi.start, 'function');
    assert.equal(typeof vi.stop, 'function');
    assert.equal(typeof vi.isListening, 'function');
  });

  it('isSupported returns a boolean', function() {
    const vi = createVoiceInput();
    const result = vi.isSupported();
    assert.equal(typeof result, 'boolean');
  });

  it('isListening starts as false', function() {
    const vi = createVoiceInput();
    assert.equal(vi.isListening(), false);
  });

  it('accepts options with lang property', function() {
    const vi = createVoiceInput({ lang: 'fr-FR' });
    assert.ok(vi);
    assert.equal(typeof vi.start, 'function');
  });

  it('stop sets listening to false', function() {
    const vi = createVoiceInput();
    vi.stop();
    assert.equal(vi.isListening(), false);
  });

  it('start returns false when not supported (no window)', function() {
    const vi = createVoiceInput();
    const result = vi.start(function() {}, function() {});
    assert.equal(result, false);
  });
});

patterns.code:
function createCacheStrategy(cacheName, precacheUrls) {
  const name = cacheName || 'app-cache-v1';
  const urls = precacheUrls || ['/'];

  function getPrecacheUrls() { return urls.slice(); }
  function getCacheName() { return name; }

  function shouldCache(url) {
    if (!url) return false;
    try {
      const parsed = new URL(url, 'https://localhost');
      if (parsed.pathname.startsWith('/api/')) return false;
      return true;
    } catch { return false; }
  }

  function isGetRequest(method) {
    return method === 'GET';
  }

  return { getPrecacheUrls, getCacheName, shouldCache, isGetRequest };
}

patterns.testCode:
const { describe, it } = require('node:test');
const assert = require('node:assert/strict');

describe('createCacheStrategy', function() {
  it('getCacheName returns the provided cache name', function() {
    const cs = createCacheStrategy('my-cache-v2', ['/']);
    assert.equal(cs.getCacheName(), 'my-cache-v2');
  });

  it('getCacheName returns default when not provided', function() {
    const cs = createCacheStrategy();
    assert.equal(cs.getCacheName(), 'app-cache-v1');
  });

  it('getPrecacheUrls returns a copy of the urls array', function() {
    const urls = ['/', '/about', '/contact'];
    const cs = createCacheStrategy('cache', urls);
    const result = cs.getPrecacheUrls();
    assert.deepEqual(result, ['/', '/about', '/contact']);
    result.push('/extra');
    assert.equal(cs.getPrecacheUrls().length, 3);
  });

  it('getPrecacheUrls defaults to ["/"]', function() {
    const cs = createCacheStrategy();
    assert.deepEqual(cs.getPrecacheUrls(), ['/']);
  });

  it('shouldCache returns false for /api/ routes', function() {
    const cs = createCacheStrategy();
    assert.equal(cs.shouldCache('/api/users'), false);
    assert.equal(cs.shouldCache('/api/data/123'), false);
  });

  it('shouldCache returns true for non-api routes', function() {
    const cs = createCacheStrategy();
    assert.equal(cs.shouldCache('/'), true);
    assert.equal(cs.shouldCache('/about'), true);
    assert.equal(cs.shouldCache('/contact'), true);
  });

  it('shouldCache returns false for empty or null url', function() {
    const cs = createCacheStrategy();
    assert.equal(cs.shouldCache(''), false);
    assert.equal(cs.shouldCache(null), false);
    assert.equal(cs.shouldCache(undefined), false);
  });

  it('isGetRequest returns true for GET', function() {
    const cs = createCacheStrategy();
    assert.equal(cs.isGetRequest('GET'), true);
  });

  it('isGetRequest returns false for non-GET methods', function() {
    const cs = createCacheStrategy();
    assert.equal(cs.isGetRequest('POST'), false);
    assert.equal(cs.isGetRequest('PUT'), false);
    assert.equal(cs.isGetRequest('DELETE'), false);
  });
});

