  for (const key of keys) {
    const value = obj[key];
    if (value === undefined || value === null) continue;
    const encodedKey = encodeURIComponent(key);
    const encodedValue = encodeURIComponent(String(value));
    pairs.push(encodedKey + '=' + encodedValue);
  }
  return pairs.join('&');
}

