    const r = right(i);
    if (l < n && heap[l] < heap[smallest]) smallest = l;
    if (r < n && heap[r] < heap[smallest]) smallest = r;
    if (smallest !== i) {
      swap(i, smallest);
      bubbleDown(smallest);
    }
  }

  function insert(value) {
    heap.push(value);
    bubbleUp(heap.length - 1);
  }

  function extractMin() {
    if (heap.length === 0) return;
    const min = heap[0];
    const last = heap.pop();
    if (heap.length > 0) {
      heap[0] = last;
      bubbleDown(0);
    }
    return min;
  }

  function peek() {
    return heap.length === 0 ? undefined : heap[0];
  }

  function size() {
    return heap.length;
  }

  return { insert, extractMin, peek, size };
}

