    assert.strictEqual(obs.get(), 10);
    obs.set(20);
    assert.strictEqual(obs.get(), 20);
  });

  it('should notify subscribers on set', () => {
    const obs = createObservable('hello');
    const calls = [];
    obs.subscribe((newVal, oldVal) => calls.push({ newVal, oldVal }));
    obs.set('world');
