    let count1 = 0;
    let count2 = 0;
    obs.subscribe(() => count1++);
    obs.subscribe(() => count2++);
    obs.set(1);
    obs.set(2);
    assert.strictEqual(count1, 2);
    assert.strictEqual(count2, 2);
  });

