    const bm = createBiMap();
    assert.strictEqual(bm.size(), 0);
    bm.set('a', 1);
    bm.set('b', 2);
    assert.strictEqual(bm.size(), 2);
    bm.deleteByKey('a');
    assert.strictEqual(bm.size(), 1);
  });
