function createRateLimiter(maxCalls, windowMs) {
  const timestamps = [];

  return {
    tryCall() {
      const now = Date.now();
      // Remove timestamps outside the window
      while (timestamps.length > 0 && now - timestamps[0] >= windowMs) {
        timestamps.shift();
      }

      if (timestamps.length < maxCalls) {
        timestamps.push(now);
        return true;
      }
      return false;
    }
  };
}

