function countOccurrences(str, substr) {
  if (typeof str !== 'string' || typeof substr !== 'string') return 0;
  if (substr.length === 0) return 0;
  let count = 0;
  let pos = 0;
  while (true) {
    const idx = str.indexOf(substr, pos);
    if (idx === -1) break;
    count++;
    pos = idx + substr.length;
  }
  return count;
}

