function isEmpty(val) {
  if (val === null || val === undefined) {
    return true;
  }
  if (typeof val === 'string' || Array.isArray(val)) {
    return val.length === 0;
  }
  if (typeof val === 'object') {
    return Object.keys(val).length === 0;
  }
  return false;
}

