    const results = [];
    emitter.on('data', (v) => results.push(v * 2));
    emitter.on('data', (v) => results.push(v * 3));
    emitter.emit('data', 5);
    assert.deepEqual(results, [10, 15]);
  });

  it('should remove listeners with off', () => {
