/**
 * Sorted Array — array that maintains sort order on insert
 * createSortedArray(compareFn?) → { insert, remove, indexOf, toArray, size }
 */
function createSortedArray(compareFn) {
  const compare = compareFn || ((a, b) => (a < b ? -1 : a > b ? 1 : 0));
  const items = [];

  function binarySearch(value) {
    let lo = 0;
    let hi = items.length;
    while (lo < hi) {
      const mid = (lo + hi) >>> 1;
      if (compare(items[mid], value) < 0) {
        lo = mid + 1;
      } else {
        hi = mid;
      }
    }
    return lo;
  }

  function insert(value) {
    const index = binarySearch(value);
    items.splice(index, 0, value);
  }

  function remove(value) {
    const index = binarySearch(value);
    if (index < items.length && compare(items[index], value) === 0) {
      items.splice(index, 1);
      return true;
    }
    return false;
  }

  function indexOf(value) {
    const index = binarySearch(value);
    if (index < items.length && compare(items[index], value) === 0) {
      return index;
    }
    return -1;
  }

  function toArray() {
    return items.slice();
  }

  function size() {
    return items.length;
  }

  return { insert, remove, indexOf, toArray, size };
}

module.exports = { createSortedArray };

/**
 * Stack — LIFO data structure
 * createStack() → { push, pop, peek, size, isEmpty }
 */
function createStack() {
  const items = [];

  function push(value) {
    items.push(value);
  }

  function pop() {
    if (items.length === 0) return undefined;
    return items.pop();
  }

  function peek() {
    if (items.length === 0) return undefined;
    return items[items.length - 1];
  }

  function size() {
    return items.length;
  }

  function isEmpty() {
    return items.length === 0;
  }

  return { push, pop, peek, size, isEmpty };
}

module.exports = { createStack };

/**
 * Queue — FIFO data structure
 * createQueue() → { enqueue, dequeue, peek, size, isEmpty }
 */
function createQueue() {
  const items = [];
  let front = 0;

  function enqueue(value) {
    items.push(value);
  }

  function dequeue() {
    if (front >= items.length) return undefined;
    const value = items[front];
    items[front] = undefined; // allow GC
    front++;
    // compact when half the array is empty
    if (front > items.length / 2 && front > 10) {
      items.splice(0, front);
      front = 0;
    }
    return value;
  }

  function peek() {
    if (front >= items.length) return undefined;
    return items[front];
  }

  function size() {
    return items.length - front;
  }

  function isEmpty() {
    return size() === 0;
  }

  return { enqueue, dequeue, peek, size, isEmpty };
}

module.exports = { createQueue };

/**
 * BiMap — bidirectional map (bijection between keys and values)
 * createBiMap() → { set, getByKey, getByValue, deleteByKey, deleteByValue, size }
 */
function createBiMap() {
  const forward = new Map();  // key → value
  const reverse = new Map();  // value → key

  function set(key, value) {
    // Remove existing mappings if they conflict
    if (forward.has(key)) {
      const oldValue = forward.get(key);
      reverse.delete(oldValue);
    }
    if (reverse.has(value)) {
      const oldKey = reverse.get(value);
      forward.delete(oldKey);
    }
    forward.set(key, value);
    reverse.set(value, key);
  }

  function getByKey(key) {
    return forward.get(key);
  }

  function getByValue(value) {
    return reverse.get(value);
  }

  function deleteByKey(key) {
    if (!forward.has(key)) return false;
    const value = forward.get(key);
    forward.delete(key);
    reverse.delete(value);
    return true;
  }

  function deleteByValue(value) {
    if (!reverse.has(value)) return false;
    const key = reverse.get(value);
    reverse.delete(value);
    forward.delete(key);
    return true;
  }

  function size() {
    return forward.size;
  }

  return { set, getByKey, getByValue, deleteByKey, deleteByValue, size };
}

module.exports = { createBiMap };

/**
 * Matrix operations — matrixMultiply, matrixTranspose, matrixAdd
 * Matrices are represented as 2D arrays (array of rows).
 */
function matrixMultiply(a, b) {
  const rowsA = a.length;
  const colsA = a[0].length;
  const colsB = b[0].length;
  if (colsA !== b.length) {
    throw new Error('Incompatible matrix dimensions for multiplication');
  }
  const result = [];
  for (let i = 0; i < rowsA; i++) {
    result[i] = [];
    for (let j = 0; j < colsB; j++) {
      let sum = 0;
      for (let k = 0; k < colsA; k++) {
        sum += a[i][k] * b[k][j];
      }
      result[i][j] = sum;
    }
  }
  return result;
}

function matrixTranspose(matrix) {
  const rows = matrix.length;
  const cols = matrix[0].length;
  const result = [];
  for (let j = 0; j < cols; j++) {
    result[j] = [];
    for (let i = 0; i < rows; i++) {
      result[j][i] = matrix[i][j];
    }
  }
  return result;
}

function matrixAdd(a, b) {
  if (a.length !== b.length || a[0].length !== b[0].length) {
    throw new Error('Matrices must have the same dimensions for addition');
  }
  const result = [];
  for (let i = 0; i < a.length; i++) {
    result[i] = [];
    for (let j = 0; j < a[0].length; j++) {
      result[i][j] = a[i][j] + b[i][j];
    }
  }
  return result;
}

module.exports = { matrixMultiply, matrixTranspose, matrixAdd };

/**
 * Linked List — singly linked list data structure
 * createLinkedList() → { append, prepend, toArray, size, find, remove }
 */
function createLinkedList() {
  let head = null;
  let length = 0;

  function append(value) {
    const node = { value, next: null };
    if (!head) {
      head = node;
    } else {
      let current = head;
      while (current.next) {
        current = current.next;
      }
      current.next = node;
    }
    length++;
  }

  function prepend(value) {
    const node = { value, next: head };
    head = node;
    length++;
  }

  function toArray() {
    const result = [];
    let current = head;
    while (current) {
      result.push(current.value);
      current = current.next;
    }
    return result;
  }

  function size() {
    return length;
  }

  function find(predicate) {
    let current = head;
    while (current) {
      if (predicate(current.value)) {
        return current.value;
      }
      current = current.next;
    }
    return undefined;
  }

  function remove(value) {
    if (!head) return false;
    if (head.value === value) {
      head = head.next;
      length--;
      return true;
    }
    let current = head;
    while (current.next) {
      if (current.next.value === value) {
        current.next = current.next.next;
        length--;
        return true;
      }
      current = current.next;
    }
    return false;
  }

  return { append, prepend, toArray, size, find, remove };
}

module.exports = { createLinkedList };

/**
 * wrapText - Wraps text to a specified width by inserting newlines between words.
 * @param {string} str - The text to wrap.
 * @param {number} width - The maximum line width.
 * @returns {string} The wrapped text with newline characters.
 */
function wrapText(str, width) {
  if (typeof str !== 'string') return '';
  if (width <= 0) return str;
  const words = str.split(/\s+/).filter(Boolean);
  if (words.length === 0) return '';
  const lines = [];
  let currentLine = words[0];
  for (let i = 1; i < words.length; i++) {
    if (currentLine.length + 1 + words[i].length <= width) {
      currentLine += ' ' + words[i];
    } else {
      lines.push(currentLine);
      currentLine = words[i];
    }
  }
  lines.push(currentLine);
  return lines.join('\n');
}

module.exports = wrapText;

/**
 * Observable — reactive value with subscriptions
 * createObservable(initialValue) → { get, set, subscribe, unsubscribe }
 */
function createObservable(initialValue) {
  let value = initialValue;
  const listeners = new Map();
  let nextId = 0;

  function get() {
    return value;
  }

  function set(newValue) {
    const oldValue = value;
    value = newValue;
    for (const [, listener] of listeners) {
      listener(newValue, oldValue);
    }
  }

  function subscribe(listener) {
    const id = nextId++;
    listeners.set(id, listener);
    return id;
  }

  function unsubscribe(id) {
    return listeners.delete(id);
  }

  return { get, set, subscribe, unsubscribe };
}

module.exports = { createObservable };

/**
 * Generates an array of numbers from start (inclusive) to end (exclusive).
 * @param {number} start - The start of the range.
 * @param {number} end - The end of the range (exclusive).
 * @param {number} [step=1] - The step between values.
 * @returns {number[]} An array of numbers.
 */
function range(start, end, step) {
  if (step === 0) {
    throw new RangeError('step must not be zero');
  }
  const s = step !== undefined ? step : (start <= end ? 1 : -1);
  const result = [];
  if (s > 0) {
    for (let i = start; i < end; i += s) {
      result.push(i);
    }
  } else {
    for (let i = start; i > end; i += s) {
      result.push(i);
    }
  }
  return result;
}

module.exports = range;

// Guarded API helpers — abort-safe, single-flight request pattern
// Wraps fetch to enforce guarded access (no raw fetch in components)

function createApiClient(fetchFn) {
  async function apiGet(url, signal) {
    const res = await fetchFn(url, { signal });
    if (!res.ok) {
      const body = await res.json().catch(() => null);
      throw new Error((body && body.error) || `GET ${url} failed (${res.status})`);
    }
    return res.json();
  }

  async function apiPost(url, data, signal) {
    const res = await fetchFn(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
      signal,
    });
    if (!res.ok) {
      const body = await res.json().catch(() => null);
      throw new Error((body && body.error) || `POST ${url} failed (${res.status})`);
    }
    return res.json();
  }

  return { apiGet, apiPost };
}

module.exports = { createApiClient };

// Back-to-top — scroll-to-top with throttled visibility detection
// Appears after scrolling past threshold, smooth scrolls to top

function createBackToTop(threshold = 300, throttleMs = 150) {
  let visible = false;
  let lastCall = 0;

  function checkVisibility() {
    const now = Date.now();
    if (now - lastCall < throttleMs) return visible;
    lastCall = now;
    visible = (typeof window !== 'undefined') && window.scrollY > threshold;
    return visible;
  }

  function scrollToTop() {
    if (typeof window !== 'undefined') {
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }

  return { checkVisibility, scrollToTop, get visible() { return visible; } };
}

module.exports = { createBackToTop };

/**
 * Reflection Loop — the iterative refinement engine.
 * Generates candidates, scores them, selects winners, and repeats.
 */

// Lazy-load to break circular dependency (coherency → unified/coherency → reflector → coherency)
let _computeCoherencyScore, _detectLanguage;
function _getCoherency() {
  if (!_computeCoherencyScore) {
