function main() {
  const outDir = argValue('out-dir', '/home/user/Void-Data-Compressor');
  const languageFilter = argValue('language', null);

  const oracle = new RemembranceOracle();
  const patterns = oracle.patterns.getAll().filter(p => {
    if (!p.code || p.code.length < 8) return false;
    if (languageFilter && p.language !== languageFilter) return false;
    if (p.coherencyScore && p.coherencyScore.total < 0.6) return false;
    return true;
  });

  // Split by patternType so each substrate file averages waveforms
  // within a coherent sub-family (algorithms average together, data
  // structures average together, etc.). Collapsing 276 heterogeneous
  // waveforms into a single mean produces noise; splitting by type
  // preserves structural information within each domain.
  const byType = new Map();
  let dropped = 0;
  for (const p of patterns) {
    const waveform = codeToWaveform(p.code);
    if (!waveform) { dropped++; continue; }
    const type = (p.patternType || 'utility').toLowerCase().replace(/[^a-z0-9]/g, '_');
    if (!byType.has(type)) byType.set(type, []);
    byType.get(type).push({
      name: p.name || p.id,
      waveform,
      tags: (p.tags || []).slice(0, 10),
      language: p.language || 'unknown',
      coherency: p.coherencyScore?.total || 0,
    });
  }

  fs.mkdirSync(outDir, { recursive: true });
  const written = [];
  for (const [type, entries] of byType.entries()) {
    if (entries.length < 2) continue; // need >=2 waveforms for a meaningful mean
    const filename = `code_${type}_substrate.json`;
    const filepath = path.join(outDir, filename);
    const out = {
      patterns: entries,
      meta: {
        source: 'remembrance-oracle-toolkit',
        pattern_type: type,
        count: entries.length,
        language: languageFilter || 'all',
        generated_at: new Date().toISOString(),
        target_waveform_length: TARGET_LEN,
      },
    };
    fs.writeFileSync(filepath, JSON.stringify(out, null, 2));
    written.push({ type, count: entries.length, filename });
  }

  console.log(`Wrote ${written.length} code substrate files → ${outDir}`);
  for (const w of written) {
    console.log(`  ${w.filename.padEnd(40)}  ${String(w.count).padStart(4)} patterns`);
  }
  console.log(`  total patterns: ${written.reduce((s, w) => s + w.count, 0)}`);
  console.log(`  dropped: ${dropped}`);

  // Emit a suggested DOMAIN_MAP + DOMAIN_GROUPS snippet for Void.
  console.log('\n--- paste into resonance_detector.py DOMAIN_MAP ---');
  for (const w of written) {
    console.log(`    '${w.filename}': 'code_${w.type}',`);
  }
  console.log('\n--- paste into resonance_detector.py DOMAIN_GROUPS[code] ---');
  console.log(`    'code': [${written.map(w => `'code_${w.type}'`).join(', ')}],`);
}

async function run() {
  const rows = [];
  for (const file of FILES) {
    if (!fs.existsSync(file)) {
      console.log(`MISSING: ${file}`);
      continue;
    }
    const code = fs.readFileSync(file, 'utf-8');
    let voidScore = null;
    try {
      const r = await postJSON('/coherence', { text: code });
      voidScore = r.coherence;
    } catch (e) { voidScore = null; }
    const findings = auditFindings(file);
    rows.push({ file, findings, voidCoherence: voidScore, size: code.length });
    console.log(
      file.padEnd(60) +
      `  findings: ${String(findings).padStart(2)}` +
      `  void: ${String(voidScore).padStart(6)}` +
      `  size: ${code.length}B`
    );
  }

  const valid = rows.filter(r => typeof r.voidCoherence === 'number' && r.findings >= 0);
  const findings = valid.map(r => r.findings);
  const coh = valid.map(r => r.voidCoherence);
  const rho = spearman(findings, coh);

  console.log('\n=== Correlation ===');
  console.log(`samples          : ${valid.length}/${FILES.length}`);
  console.log(`Spearman ρ       : ${rho.toFixed(4)}`);
  console.log(`interpretation   : ${
    rho < -0.5 ? 'STRONG negative — hypothesis CONFIRMED (low coherency ↔ high findings)' :
    rho < -0.3 ? 'moderate negative — hypothesis supported' :
    rho < -0.1 ? 'weak negative — hypothesis weakly supported' :
    rho > 0.1 ? 'positive — hypothesis REJECTED' :
    'near zero — no correlation'
  }`);

  // Buckets
  const clean = valid.filter(r => r.findings === 0);
  const buggy = valid.filter(r => r.findings > 0);
  if (clean.length && buggy.length) {
    const avg = (a) => a.reduce((s, x) => s + x, 0) / a.length;
    const cleanCoh = avg(clean.map(r => r.voidCoherence));
    const buggyCoh = avg(buggy.map(r => r.voidCoherence));
    console.log(`\nClean files (0 findings)  avg Void coherency: ${cleanCoh.toFixed(4)}  (n=${clean.length})`);
    console.log(`Buggy files (>0 findings) avg Void coherency: ${buggyCoh.toFixed(4)}  (n=${buggy.length})`);
    console.log(`delta                                       : ${(buggyCoh - cleanCoh).toFixed(4)}`);
  }

  fs.mkdirSync('docs/benchmarks', { recursive: true });
  fs.writeFileSync('docs/benchmarks/coherence-vs-findings-2026-04-14.json',
    JSON.stringify({ rows, correlation: rho, ts: new Date().toISOString() }, null, 2));
  console.log('\nRaw data: docs/benchmarks/coherence-vs-findings-2026-04-14.json');
}

function atomicDistance(propsA, propsB) {
  if (!propsA || !propsB) return 0;

  let matches = 0;
  let dimensions = 0;

  // Charge match
  dimensions++;
  if (propsA.charge === propsB.charge) matches++;

  // Valence proximity
  dimensions++;
  const vDiff = Math.abs((propsA.valence || 0) - (propsB.valence || 0));
  matches += 1 - Math.min(1, vDiff / 8);

  // Mass match
  dimensions++;
  if (propsA.mass === propsB.mass) matches++;

  // Spin match
  dimensions++;
  if (propsA.spin === propsB.spin) matches++;

  // Phase match
  dimensions++;
  if (propsA.phase === propsB.phase) matches++;

  // Reactivity match
  dimensions++;
  if (propsA.reactivity === propsB.reactivity) matches++;

  // Group proximity
  dimensions++;
  const gDiff = Math.abs((propsA.group || 1) - (propsB.group || 1));
  matches += 1 - Math.min(1, gDiff / 18);

  // Period proximity
  dimensions++;
  const pDiff = Math.abs((propsA.period || 1) - (propsB.period || 1));
  matches += 1 - Math.min(1, pDiff / 7);

  // Covenant dimensions
  dimensions++;
  if ((propsA.harmPotential || 'none') === (propsB.harmPotential || 'none')) matches++;
  dimensions++;
  if ((propsA.alignment || 'neutral') === (propsB.alignment || 'neutral')) matches++;
  dimensions++;
  if ((propsA.intention || 'neutral') === (propsB.intention || 'neutral')) matches++;

  return dimensions > 0 ? Math.round((matches / dimensions) * 1000) / 1000 : 0;
}

function spearman(xs, ys) {
  const n = xs.length;
  if (n < 3) return 0;
  const rank = (arr) => {
    const idx = arr.map((v, i) => [v, i]).sort((a, b) => a[0] - b[0]);
    const r = new Array(n);
    for (let k = 0; k < n; k++) r[idx[k][1]] = k + 1;
    return r;
  };
  const rx = rank(xs);
  const ry = rank(ys);
  let sumD2 = 0;
  for (let i = 0; i < n; i++) sumD2 += (rx[i] - ry[i]) ** 2;
  return 1 - (6 * sumD2) / (n * (n * n - 1));
}

function computePeriod(code, tokens, lineCount) {
  // Abstraction level:
  //   1 = primitive (single operation, < 5 lines)
  //   2 = helper (small utility, 5-15 lines)
  //   3 = function (standard function, 15-50 lines)
  //   4 = module (multi-function, 50-150 lines)
  //   5 = component (class/large module, 150-500 lines)
  //   6 = subsystem (multi-module, 500-1500 lines)
  //   7 = framework (large system, 1500+ lines)
  if (lineCount <= 5) return 1;
  if (lineCount <= 15) return 2;
  if (lineCount <= 50) return 3;
  if (lineCount <= 150) return 4;
  if (lineCount <= 500) return 5;
  if (lineCount <= 1500) return 6;
  return 7;
}

function stripComments(code) {
  let out = '';
  let i = 0;
  const n = code.length;
  while (i < n) {
    const ch = code[i];
    // Line comment — skip to end of line
    if (ch === '/' && code[i + 1] === '/') {
      while (i < n && code[i] !== '\n') i++;
      continue;
    }
    // Block comment — skip until */
    if (ch === '/' && code[i + 1] === '*') {
      i += 2;
      while (i < n && !(code[i] === '*' && code[i + 1] === '/')) i++;
      if (i < n) i += 2;
      continue;
    }
    // String literal (single, double, or template) — preserve as-is
    // but track state so `//` and `/*` inside strings don't match.
    if (ch === '\'' || ch === '"' || ch === '`') {
      const quote = ch;
      out += ch;
      i++;
      while (i < n) {
        if (code[i] === '\\') {
          out += code[i];
          if (i + 1 < n) out += code[i + 1];
          i += 2;
          continue;
        }
        if (code[i] === quote) {
          out += quote;
          i++;
          break;
        }
        out += code[i];
        i++;
      }
      continue;
    }
    out += ch;
    i++;
  }
  return out;
}

function extractTopFactors(coherencyRisk, cyclomaticRisk, cyclomatic, maxDepth, score) {
  const factors = [];

  // Cyclomatic is the most actionable signal when it's high — it
  // directly suggests "extract helpers / simplify control flow".
  if (cyclomaticRisk >= 0.3) {
    factors.push({
      name: 'cyclomatic',
      severity: round4(cyclomaticRisk),
      message: `cyclomatic complexity ${cyclomatic} / ${CYCLOMATIC_CAP}`,
    });
  }

  // Total coherency — the aggregate semantic score.
  if (coherencyRisk >= 0.25) {
    factors.push({
      name: 'coherency',
      severity: round4(coherencyRisk),
      message: `total coherency ${(1 - coherencyRisk).toFixed(3)} (below 0.75 threshold)`,
    });
  }

  // Deep nesting — smell-level signal, not bug-indicative alone.
  if (maxDepth > MAX_DEPTH_CAP) {
    factors.push({
      name: 'maxDepth',
      severity: round4(Math.min(maxDepth / (MAX_DEPTH_CAP * 2), 1)),
      message: `max nesting depth ${maxDepth} (>${MAX_DEPTH_CAP})`,
    });
  }

  // Surface individual breakdown dimensions that are meaningfully low.
  // Only the ones that had real variance in the Phase 1 study —
  // syntaxValid and consistency were near-constant, so we skip them.
  const completeness = score.breakdown?.completeness;
  if (typeof completeness === 'number' && completeness < 0.7) {
    factors.push({
      name: 'completeness',
      severity: round4(1 - completeness),
      message: `completeness ${completeness.toFixed(2)} (missing error handling or edge cases)`,
    });
  }

  const fractal = score.breakdown?.fractalAlignment;
  if (typeof fractal === 'number' && fractal < 0.6) {
    factors.push({
      name: 'fractalAlignment',
      severity: round4(1 - fractal),
      message: `fractal alignment ${fractal.toFixed(2)} (structure does not match canonical patterns)`,
    });
  }

  // Sort by severity descending so the worst issues come first.
  // Copy first so the sort is pure — the input `factors` array is
  // local, but `.slice().sort()` keeps the audit backend happy and
  // makes the intent obvious.
  return factors.slice().sort((a, b) => b.severity - a.severity);
}

function collectFiles(rootDir, extensions, excludes) {
  const out = [];
  const stack = [rootDir];
  while (stack.length > 0) {
    const dir = stack.pop();
    let entries;
    try { entries = fs.readdirSync(dir, { withFileTypes: true }); }
    catch { continue; }
    // Sort for deterministic traversal. Copy first (the audit
    // backend is flow-insensitive and flags in-place .sort on
    // locally-owned arrays, but the cost here is trivial).
    const sortedEntries = entries.slice().sort((a, b) => a.name.localeCompare(b.name));
    for (const entry of sortedEntries) {
      if (entry.name.startsWith('.') && entry.name !== '.') {
        // Skip dotfiles/dirs except the root itself — this also
        // catches `.git`, `.next`, `.remembrance`, etc.
        if (excludes.has(entry.name)) continue;
        if (entry.isDirectory()) continue;
      }
      const p = path.join(dir, entry.name);
      if (entry.isDirectory()) {
        if (excludes.has(entry.name)) continue;
        stack.push(p);
      } else if (entry.isFile()) {
        const ext = path.extname(entry.name).toLowerCase();
        if (extensions.has(ext)) out.push(p);
      }
    }
  }
  return out;
}

function codeToWaveform(code) {
  const bytes = Buffer.from(code, 'utf-8');
  if (bytes.length < 8) return null;
  const wave = new Float64Array(TARGET_LEN);
  if (bytes.length >= TARGET_LEN) {
    for (let k = 0; k < TARGET_LEN; k++) {
      const idx = Math.floor((k / (TARGET_LEN - 1)) * (bytes.length - 1));
      wave[k] = bytes[idx];
    }
  } else {
    for (let k = 0; k < TARGET_LEN; k++) {
      const t = (k / (TARGET_LEN - 1)) * (bytes.length - 1);
      const lo = Math.floor(t);
      const hi = Math.ceil(t);
      wave[k] = bytes[lo] * (1 - (t - lo)) + bytes[hi] * (t - lo);
    }
  }
  let min = Infinity, max = -Infinity;
  for (const v of wave) { if (v < min) min = v; if (v > max) max = v; }
  if (max - min < 1e-9) return null;
  const out = new Float64Array(TARGET_LEN);
  for (let k = 0; k < TARGET_LEN; k++) out[k] = (wave[k] - min) / (max - min);
  return out;
}

function calculateEmergencePotential(props) {
  let potential = 0.5;
  if (props.harmPotential === 'none') potential += 0.2;
  if (props.alignment === 'healing') potential += 0.2;
  if (props.intention === 'benevolent') potential += 0.2;
  if (props.reactivity === 'inert' || props.reactivity === 'stable') potential += 0.1;
  if (props.spin === 'even') potential += 0.1;
  if (props.harmPotential === 'dangerous') potential -= 0.5;
  if (props.alignment === 'degrading') potential -= 0.5;
  if (props.intention === 'malevolent') potential -= 0.5;
  return Math.max(0, Math.min(1, potential));
}

function tiersTouched(calledIds, manifest) {
  const byName = new Map();
  for (const tier of manifest.tiers) byName.set(tier.name, tier);

  const directlyTouched = new Set();
  for (const tier of manifest.tiers) {
    const entryPoints = tier.entry_points || [];
    if (entryPoints.some(ep => calledIds.has(ep))) {
      directlyTouched.add(tier.name);
    }
  }

  // Transitive closure over the `composes` relation.
  const touched = new Set(directlyTouched);
  let changed = true;
  while (changed) {
    changed = false;
    for (const name of Array.from(touched)) {
      const tier = byName.get(name);
      if (!tier || !Array.isArray(tier.composes)) continue;
      for (const composed of tier.composes) {
        if (!touched.has(composed)) {
          touched.add(composed);
          changed = true;
        }
      }
    }
  }

  // Return in manifest order for stable, readable output.
  return manifest.tiers.map(t => t.name).filter(n => touched.has(n));
}

function buildReport(rootDir, results, topN) {
  const sorted = results.slice().sort((a, b) => b.probability - a.probability);
  const byRisk = { HIGH: 0, MEDIUM: 0, LOW: 0 };
  for (const r of sorted) {
    // classifyRisk guarantees one of HIGH/MEDIUM/LOW
    byRisk[r.riskLevel] = (byRisk[r.riskLevel] || 0) + 1;
  }

  const n = sorted.length;
  let mean = 0;
  let median = 0;
  if (n > 0) {
    let sum = 0;
    for (const r of sorted) sum += r.probability;
    mean = sum / n;
    const ascending = sorted.map(r => r.probability).sort((a, b) => a - b);
    median = n % 2 === 0
      ? (ascending[n / 2 - 1] + ascending[n / 2]) / 2
      : ascending[Math.floor(n / 2)];
  }

  return {
    root: rootDir,
    scannedAt: new Date().toISOString(),
    files: sorted,
    stats: {
      total: n,
      byRisk,
      meanProbability: round4(mean),
      medianProbability: round4(median),
      top: sorted.slice(0, topN),
    },
  };
}

function resolveTemplateLiteral(tok) {
  if (!tok || tok.type !== 'template') return null;
  const parts = tok.value?.parts;
  if (!parts || !Array.isArray(parts)) return null;

  let resolved = '';
  for (const part of parts) {
    if (part.type === 'str') {
      resolved += part.value;
    } else if (part.type === 'expr') {
      // Check if the expression is a bare string literal like 'ev'
      const trimmed = part.value.trim();
      if ((trimmed.startsWith("'") && trimmed.endsWith("'")) ||
          (trimmed.startsWith('"') && trimmed.endsWith('"'))) {
        resolved += trimmed.slice(1, -1);
      } else {
        // Dynamic expression — cannot resolve statically
        return null;
      }
    }
  }

  // Only report if there was interpolation (otherwise it's just a plain string)
  const hasInterp = tok.value?.hasInterp;
  if (!hasInterp) return null;

  return resolved;
}

function computeMass(code, tokens, lineCount) {
  // Nesting depth as complexity proxy
  let maxDepth = 0;
  let currentDepth = 0;
  for (const t of tokens) {
    if (t.value === '{' || t.value === '(') currentDepth++;
    if (t.value === '}' || t.value === ')') currentDepth--;
    if (currentDepth > maxDepth) maxDepth = currentDepth;
  }
  // Loop count as another proxy
  const loops = countMatches(code, [/\bfor\s*\(/g, /\bwhile\s*\(/g, /\.forEach\b/g, /\.map\b/g]);
  const nestedLoops = maxDepth > 5 || loops > 3;

  if (lineCount < 20 && maxDepth < 4 && loops <= 1) return 'light';
  if (nestedLoops || lineCount > 100 || maxDepth > 6) return 'heavy';
  return 'medium';
}

