/**
 * Admin Session — Cookie-based session for admin dashboard access.
 *
 * Uses HMAC-SHA256 signed cookies so the middleware can verify sessions
 * without hitting a database. The signature prevents tampering.
 *
 * Cookie format: <payload>.<signature>
 * Payload: base64url(JSON.stringify({ exp, email?, role? }))
 *
 * Supports two token types:
 *  1. Legacy: { exp } — from API key login (backward compatible)
 *  2. Google: { exp, email, role } — from Google OAuth sign-in
 */

import { createHmac } from "crypto";

const COOKIE_NAME = "__admin_session";
const SESSION_DURATION_S = 8 * 60 * 60; // 8 hours

export interface SessionPayload {
  exp: number;
  email?: string;
  role?: "admin" | "user";
}

function getSecret(): string {
  const key = process.env.ADMIN_API_KEY ?? process.env.NEXTAUTH_SECRET;
  if (!key) throw new Error("ADMIN_API_KEY or NEXTAUTH_SECRET must be set");
  return key;
}

function sign(payload: string): string {
  return createHmac("sha256", getSecret())
    .update(payload)
    .digest("base64url");
}

/** Create a signed session token with an expiration time (legacy API key login). */
export function createSessionToken(): string {
  const exp = Math.floor(Date.now() / 1000) + SESSION_DURATION_S;
  const payload = Buffer.from(JSON.stringify({ exp })).toString("base64url");
  const sig = sign(payload);
  return `${payload}.${sig}`;
}

/** Create a signed session token with email and role (Google OAuth login). */
export function createGoogleSessionToken(
  email: string,
  role: "admin" | "user",
): string {
  const exp = Math.floor(Date.now() / 1000) + SESSION_DURATION_S;
  const payload = Buffer.from(
    JSON.stringify({ exp, email, role }),
  ).toString("base64url");
  const sig = sign(payload);
  return `${payload}.${sig}`;
}

/** Verify a session token. Returns true if valid and not expired. */
export function verifySessionToken(token: string): boolean {
  const result = verifyAndDecodeSessionToken(token);
  return result !== null;
}

/** Verify and decode a session token. Returns the payload if valid, null otherwise. */
export function verifyAndDecodeSessionToken(
  token: string,
): SessionPayload | null {
  try {
    const [payload, sig] = token.split(".");
    if (!payload || !sig) return null;

    const expectedSig = sign(payload);

    // Constant-time comparison
    if (sig.length !== expectedSig.length) return null;
    let mismatch = 0;
    for (let i = 0; i < sig.length; i++) {
      mismatch |= sig.charCodeAt(i) ^ expectedSig.charCodeAt(i);
    }
    if (mismatch !== 0) return null;

    const data = JSON.parse(
      Buffer.from(payload, "base64url").toString("utf-8"),
    );
    if (typeof data.exp !== "number") return null;
    if (data.exp <= Math.floor(Date.now() / 1000)) return null;

    return {
      exp: data.exp,
      email: data.email ?? undefined,
      role: data.role ?? undefined,
    };
  } catch {
    return null;
  }
}

export const ADMIN_SESSION_COOKIE = COOKIE_NAME;
export const ADMIN_SESSION_MAX_AGE = SESSION_DURATION_S;

/**
 * Creates a new object with only the specified keys from the source object.
 * @param {Object} obj - The source object.
 * @param {string[]} keys - The keys to pick.
 * @returns {Object} A new object containing only the picked keys.
 */
function pick(obj, keys) {
  const result = {};
  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    if (Object.prototype.hasOwnProperty.call(obj, key)) {
      result[key] = obj[key];
    }
  }
  return result;
}

module.exports = pick;

/**
 * Creates a new object with the specified keys omitted from the source object.
 * @param {Object} obj - The source object.
 * @param {string[]} keys - The keys to omit.
 * @returns {Object} A new object without the omitted keys.
 */
function omit(obj, keys) {
  const keysToOmit = new Set(keys);
  const result = {};
  const allKeys = Object.keys(obj);
  for (let i = 0; i < allKeys.length; i++) {
    const key = allKeys[i];
    if (!keysToOmit.has(key)) {
      result[key] = obj[key];
    }
  }
  return result;
}

module.exports = omit;

/**
 * useUtmTracking — Capture and persist UTM parameters across the session.
 *
 * Captures utm_source, utm_medium, utm_campaign, utm_term, utm_content
 * from the URL on first load, persists them in sessionStorage so they
 * survive navigation within the site. Exposes them for form submission.
 *
 * Also captures referrer and landing page for attribution.
 */
import { useEffect, useState } from "react";

export interface UtmParams {
  utmSource: string | null;
  utmMedium: string | null;
  utmCampaign: string | null;
  utmTerm: string | null;
  utmContent: string | null;
  referrer: string | null;
  landingPage: string | null;
}

const STORAGE_KEY = "dc_utm";

const UTM_KEYS = [
  ["utm_source", "utmSource"],
  ["utm_medium", "utmMedium"],
  ["utm_campaign", "utmCampaign"],
  ["utm_term", "utmTerm"],
  ["utm_content", "utmContent"],
] as const;

function captureFromUrl(): UtmParams {
  const params = new URLSearchParams(window.location.search);
  const utm: UtmParams = {
    utmSource: null,
    utmMedium: null,
    utmCampaign: null,
    utmTerm: null,
    utmContent: null,
    referrer: document.referrer || null,
    landingPage: window.location.href,
  };

  for (const [urlKey, stateKey] of UTM_KEYS) {
    const value = params.get(urlKey);
    if (value) {
      utm[stateKey] = value;
    }
  }

  return utm;
}

function loadFromStorage(): UtmParams | null {
  try {
    const stored = sessionStorage.getItem(STORAGE_KEY);
    return stored ? JSON.parse(stored) : null;
  } catch {
    return null;
  }
}

function saveToStorage(utm: UtmParams): void {
  try {
    sessionStorage.setItem(STORAGE_KEY, JSON.stringify(utm));
  } catch {
    // Storage unavailable — silent fail
  }
}

export function useUtmTracking(): UtmParams {
  const [utm, setUtm] = useState<UtmParams>({
    utmSource: null,
    utmMedium: null,
    utmCampaign: null,
    utmTerm: null,
    utmContent: null,
    referrer: null,
    landingPage: null,
  });

  useEffect(() => {
    // Priority: URL params (fresh click) > sessionStorage (persisted)
    const fromUrl = captureFromUrl();
    const hasUrlUtm = UTM_KEYS.some(([_, key]) => fromUrl[key] !== null);

    if (hasUrlUtm) {
      // Fresh click with UTM params — save and use
      saveToStorage(fromUrl);
      setUtm(fromUrl);
    } else {
      // No UTM in URL — check session storage
      const stored = loadFromStorage();
      if (stored) {
        setUtm(stored);
      } else {
        // First visit with no UTM — save referrer/landing page
        saveToStorage(fromUrl);
        setUtm(fromUrl);
      }
    }
  }, []);

  return utm;
}

/**
 * CSRF Protection
 *
 * Double-submit cookie pattern:
 *  1. Server sets a random token in an httpOnly, sameSite=strict cookie
 *  2. API endpoint /api/csrf returns the token for the client to read
 *  3. Client sends the token as X-CSRF-Token header on mutating requests
 *  4. Server validates header matches cookie value
 *
 * This works with Next.js App Router + React client components.
 */

import { NextRequest, NextResponse } from "next/server";
import { randomBytes } from "crypto";

const CSRF_COOKIE_NAME = "__csrf";
const CSRF_HEADER_NAME = "x-csrf-token";
const TOKEN_LENGTH = 32; // 256 bits of entropy

/** Generate a cryptographically secure CSRF token */
export function generateCsrfToken(): string {
  return randomBytes(TOKEN_LENGTH).toString("hex");
}

/** Read the CSRF token from the request cookie */
export function getCsrfTokenFromCookie(req: NextRequest): string | null {
  return req.cookies.get(CSRF_COOKIE_NAME)?.value ?? null;
}

/** Read the CSRF token from the request header */
export function getCsrfTokenFromHeader(req: NextRequest): string | null {
  return req.headers.get(CSRF_HEADER_NAME);
}

/**
 * Validate that the CSRF header matches the cookie.
 * Returns true if valid, false if mismatch or missing.
 */
export function validateCsrfToken(req: NextRequest): boolean {
  const cookieToken = getCsrfTokenFromCookie(req);
  const headerToken = getCsrfTokenFromHeader(req);

  if (!cookieToken || !headerToken) return false;
  if (cookieToken.length !== headerToken.length) return false;

  // Constant-time comparison to prevent timing attacks
  let mismatch = 0;
  for (let i = 0; i < cookieToken.length; i++) {
    mismatch |= cookieToken.charCodeAt(i) ^ headerToken.charCodeAt(i);
  }
  return mismatch === 0;
}

/**
 * Set the CSRF cookie on a response.
 * Call this from the /api/csrf endpoint or middleware.
 */
export function setCsrfCookie(response: NextResponse, token: string): void {
  response.cookies.set(CSRF_COOKIE_NAME, token, {
    httpOnly: true,
    secure: process.env.NODE_ENV === "production",
    sameSite: "strict",
    path: "/",
    maxAge: 60 * 60, // 1 hour
  });
}

/**
 * Admin Emails — Server-side allowlist for auto-admin role assignment.
 *
 * Reads ADMIN_EMAILS from environment (comma-separated).
 * Used during Google OAuth to determine if a user gets admin access.
 *
 * IMPORTANT: This module is server-side only. Never import from client components.
 */

function getAdminEmails(): Set<string> {
  const raw = process.env.ADMIN_EMAILS ?? "";
  const emails = raw
    .split(",")
    .map((e) => e.trim().toLowerCase())
    .filter((e) => e.length > 0);
  return new Set(emails);
}

/** Check if an email address is in the admin allowlist. */
export function isAdminEmail(email: string): boolean {
  if (!email || typeof email !== "string") return false;
  return getAdminEmails().has(email.trim().toLowerCase());
}

/** Get the role for a given email. */
export function getRoleForEmail(email: string): "admin" | "user" {
  return isAdminEmail(email) ? "admin" : "user";
}

/**
 * Date of Birth validation — minimum age enforcement.
 * Validates DOB string (YYYY-MM-DD) and ensures the person is at least 18 years old.
 */
export function validateDob(dob: string): boolean {
  if (typeof dob !== "string") return false;
  const match = dob.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!match) return false;

  const year = parseInt(match[1], 10);
  const month = parseInt(match[2], 10);
  const day = parseInt(match[3], 10);

  // Basic range checks
  if (month < 1 || month > 12) return false;
  if (day < 1 || day > 31) return false;
  if (year < 1900 || year > new Date().getFullYear()) return false;

  // Validate the date is real (e.g. no Feb 30)
  const date = new Date(year, month - 1, day);
  if (
    date.getFullYear() !== year ||
    date.getMonth() !== month - 1 ||
    date.getDate() !== day
  ) {
    return false;
  }

  return isAtLeast18(date);
}

export function isAtLeast18(birthDate: Date): boolean {
  const today = new Date();
  const eighteenYearsAgo = new Date(
    today.getFullYear() - 18,
    today.getMonth(),
    today.getDate(),
  );
  return birthDate <= eighteenYearsAgo;
}

/**
 * IP-Based Rate Limiter
 *
 * Uses an in-memory sliding window approach. Each IP gets a window of
 * timestamps. Requests beyond the limit within the window are rejected.
 * Stale entries are cleaned up automatically to prevent memory leaks.
 */

interface RateLimitEntry {
  timestamps: number[];
}

const store = new Map<string, RateLimitEntry>();
const MAX_STORE_SIZE = 10_000;

// --- Sliding window with per-IP tracking for API protection ---

/**
 * Check if an IP is rate-limited.
 * @returns { allowed: true } or { allowed: false, retryAfterMs }
 */
export function checkRateLimit(
  ip: string,
  maxRequests: number = 5,
  windowMs: number = 60_000,
): { allowed: true } | { allowed: false; retryAfterMs: number } {
  const now = Date.now();
  const entry = store.get(ip);

  if (!entry) {
    // Evict oldest entry if store is at capacity
    if (store.size >= MAX_STORE_SIZE) {
      const oldestKey = store.keys().next().value;
      if (oldestKey !== undefined) store.delete(oldestKey);
    }
    store.set(ip, { timestamps: [now] });
    return { allowed: true };
  }

  // Slide the window — remove timestamps older than windowMs
  entry.timestamps = entry.timestamps.filter((t) => now - t < windowMs);

  if (entry.timestamps.length >= maxRequests) {
    const oldest = entry.timestamps[0] ?? now;
    const retryAfterMs = Math.max(0, windowMs - (now - oldest));
    return { allowed: false, retryAfterMs };
  }

  entry.timestamps.push(now);
  return { allowed: true };
}

/**
 * Extract client IP from a request.
 * Checks x-forwarded-for, x-real-ip, then falls back to "unknown".
 */
export function getClientIp(headers: Headers): string {
  const forwarded = headers.get("x-forwarded-for");
  if (forwarded) {
    // Take the first IP in the chain (original client)
    return forwarded.split(",")[0].trim();
  }
  return headers.get("x-real-ip") || "unknown";
}

// --- Cleanup stale entries every 5 minutes to prevent memory leaks ---
const CLEANUP_INTERVAL = 5 * 60 * 1000;

function cleanup(): void {
  const now = Date.now();
  const maxAge = 10 * 60 * 1000; // Remove entries not seen in 10 minutes
  for (const [ip, entry] of store) {
    const latest = entry.timestamps[entry.timestamps.length - 1] || 0;
    if (now - latest > maxAge) {
      store.delete(ip);
    }
  }
}

setInterval(cleanup, CLEANUP_INTERVAL).unref();

function verifySymbol(symbol, context) {
  if (!symbol || typeof symbol !== 'string') {
    return { symbol: String(symbol), status: 'missing', source: null, evidence: 'invalid input' };
  }

  // Tier 1: built-in allowlist
  if (BUILTINS.has(symbol)) {
    return { symbol, status: 'builtin', source: 'js/node allowlist', evidence: null };
  }

  // Tier 2: session-touched identifiers
  if (context.knownIdentifiers && context.knownIdentifiers.has(symbol)) {
    return { symbol, status: 'seen', source: 'session ledger', evidence: 'previously read this session' };
  }

  // Tier 3: oracle pattern library
  if (context.oracle && typeof context.oracle.search === 'function') {
    try {
      const hits = context.oracle.search(symbol, { limit: 3 });
      if (Array.isArray(hits) && hits.length > 0) {
        // Require a strong match — the top hit's name must equal the
        // symbol (case-sensitive) OR contain it as a prefix. Weaker
        // text-similarity matches would let fabrications slip through.
        const top = hits[0];
        const name = top.name || top.description || '';
        if (name === symbol || name.startsWith(symbol) || (top.tags || []).includes(symbol)) {
          return {
            symbol,
            status: 'pattern',
            source: 'oracle pattern library',
            evidence: { patternName: name, coherency: top.coherency, id: top.id },
          };
        }
      }
    } catch { /* degrade gracefully */ }
  }

  // Tier 4: filesystem scan — look for a definition in the repo's src tree
  if (context.repoRoot) {
    const dirs = context.srcDirs || ['src'];
    for (const dir of dirs) {
      const abs = path.join(context.repoRoot, dir);
      if (!fs.existsSync(abs)) continue;
      const hit = scanForDefinition(abs, symbol, 200);
      if (hit) {
        return {
          symbol,
          status: 'found',
          source: 'repo scan',
          evidence: { file: path.relative(context.repoRoot, hit.file), line: hit.line },
        };
      }
    }
  }

  return { symbol, status: 'missing', source: null, evidence: 'no ground truth found' };
}

/**
 * Multi-Domain Configuration
 *
 * Separates the application into two domain groups:
 *  - Leads domains (.com, .net, .info, .store, .shop) — public marketing + lead capture only
 *  - Portal domain (.xyz) — Admin dashboard + Agent portal
 *
 * Environment variables:
 *  - LEADS_DOMAINS: comma-separated hostnames for the leads website
 *  - PORTAL_DOMAIN: hostname for the admin/agent portal
 *  - NEXT_PUBLIC_PORTAL_URL: full URL for cross-domain portal links
 */

/** Parse comma-separated domain list from env, lowercased and trimmed. */
const LEADS_DOMAINS: string[] = (process.env.LEADS_DOMAINS ?? "")
  .split(",")
  .map((d) => d.trim().toLowerCase())
  .filter(Boolean);

/** The single portal domain (admin + client). */
const PORTAL_DOMAIN: string = (process.env.PORTAL_DOMAIN ?? "").trim().toLowerCase();

export type DomainType = "leads" | "portal" | "unknown";

/**
 * Determine domain type from hostname.
 * Strips port for localhost/dev comparisons.
 */
export function getDomainType(hostname: string): DomainType {
  const host = hostname.toLowerCase().split(":")[0]; // strip port

  if (PORTAL_DOMAIN && host === PORTAL_DOMAIN) return "portal";
  if (LEADS_DOMAINS.length > 0 && LEADS_DOMAINS.includes(host)) return "leads";

  // In development (localhost) or when env vars aren't set, allow everything
  return "unknown";
}

/** Routes that should ONLY be served on the portal domain. */
export const PORTAL_ONLY_ROUTES = [
  "/admin",
  "/portal",
  "/api/admin",
  "/api/client",
  "/api/portal",
];

/** Check if a pathname belongs to portal-only routes. */
export function isPortalRoute(pathname: string): boolean {
  return PORTAL_ONLY_ROUTES.some((r) => pathname.startsWith(r));
}

/** Public URL for the portal (for cross-domain links). */
export const PORTAL_URL =
  process.env.NEXT_PUBLIC_PORTAL_URL || (PORTAL_DOMAIN ? `https://${PORTAL_DOMAIN}` : "");

export { LEADS_DOMAINS, PORTAL_DOMAIN };

/**
 * Counter — count occurrences in an array, find most common elements
 * createCounter(array) → { counts (Map), get(item), mostCommon(n), entries() }
 */
function createCounter(array) {
  const counts = new Map();

  for (const item of array) {
    counts.set(item, (counts.get(item) || 0) + 1);
  }

  function get(item) {
    return counts.get(item) || 0;
  }

  function mostCommon(n) {
    const sorted = [...counts.entries()].sort((a, b) => b[1] - a[1]);
    return sorted.slice(0, n);
  }

  function entries() {
    return [...counts.entries()];
  }

  return { counts, get, mostCommon, entries };
}

module.exports = { createCounter };

