/**
 * memoizeWithTTL - Memoizes a function with a time-to-live cache.
 * Cached results expire after ttl milliseconds.
 * @param {Function} fn - Function to memoize
 * @param {number} ttl - Time-to-live for cache entries in milliseconds
 * @returns {Function} Memoized function
 */
function memoizeWithTTL(fn, ttl) {
  const cache = new Map();

  return function (...args) {
    const key = JSON.stringify(args);
    const now = Date.now();

    if (cache.has(key)) {
      const entry = cache.get(key);
      if (now - entry.timestamp < ttl) {
        return entry.value;
      }
      cache.delete(key);
    }

    const value = fn.apply(this, args);
    cache.set(key, { value, timestamp: now });
    return value;
  };
}

module.exports = { memoizeWithTTL };

/**
 * after - Creates a function that only executes after being called n times.
 * Before n calls, returns undefined.
 * @param {number} n - Number of calls before fn executes
 * @param {Function} fn - Function to invoke after n calls
 * @returns {Function} Wrapped function
 */
function after(n, fn) {
  let count = 0;

  return function (...args) {
    count++;
    if (count >= n) {
      return fn.apply(this, args);
    }
    return undefined;
  };
}

module.exports = { after };

/**
 * once - Creates a function that runs only on the first call.
 * Subsequent calls return the result of the first invocation.
 * @param {Function} fn - Function to call once
 * @returns {Function} Wrapped function
 */
function once(fn) {
  let called = false;
  let result;

  return function (...args) {
    if (!called) {
      called = true;
      result = fn.apply(this, args);
    }
    return result;
  };
}

module.exports = { once };

/**
 * curry - Returns a curried version of the given function.
 * Curried function can be called with any number of arguments
 * and returns a new function until all arguments are collected.
 * @param {Function} fn - Function to curry
 * @returns {Function} Curried function
 */
function curry(fn) {
  const arity = fn.length;

  function curried(...args) {
    if (args.length >= arity) {
      return fn.apply(this, args);
    }
    return function (...moreArgs) {
      return curried.apply(this, args.concat(moreArgs));
    };
  }

  return curried;
}

module.exports = { curry };

/**
 * before - Creates a function that only executes for the first n calls.
 * After n calls, returns the last successful result.
 * @param {number} n - Maximum number of times fn will execute
 * @param {Function} fn - Function to invoke
 * @returns {Function} Wrapped function
 */
function before(n, fn) {
  let count = 0;
  let lastResult;

  return function (...args) {
    count++;
    if (count <= n) {
      lastResult = fn.apply(this, args);
    }
    return lastResult;
  };
}

module.exports = { before };

