export async function DELETE(req: NextRequest) {
  const { logger, finish } = startRequestTimer("DELETE", "/api/leads");

  const clientIp = getClientIp(req.headers);
  const rateCheck = checkRateLimit(clientIp, 3, 60_000); // 3 deletion requests per minute
  if (!rateCheck.allowed) {
    logger.warn("Rate limit exceeded on DELETE", { clientIp });
    finish(429);
    return NextResponse.json(
      { success: false, message: "Too many requests. Please wait before trying again." },
      { status: 429, headers: { "Retry-After": String(Math.ceil(rateCheck.retryAfterMs / 1000)) } },
    );
  }

  try {
    const body = await req.json();
    const { email } = body;

    if (!email || !isValidEmail(email)) {
      logger.warn("Invalid email on CCPA delete", { clientIp });
      finish(400);
      return NextResponse.json(
        { success: false, message: "A valid email address is required to process your deletion request." },
        { status: 400 },
      );
    }

    const result = await deleteLeadByEmail(email);

    if (!result.ok) {
      logger.error("CCPA delete failed", { error: result.error, clientIp });
      finish(500);
      return NextResponse.json(
        { success: false, message: "Something went wrong processing your request." },
        { status: 500 },
      );
    }

    logger.info("CCPA delete completed", { deleted: result.value.deleted, clientIp });
    finish(200, { deleted: result.value.deleted });

    // Always return success even if no records found (privacy — don't reveal existence)
    return NextResponse.json({
      success: true,
      message: "Your data deletion request has been processed. Any records associated with your email have been removed.",
      deleted: result.value.deleted,
    });
  } catch {
    finish(400);
    return NextResponse.json(
      { success: false, message: "Invalid request." },
      { status: 400 },
    );
  }
}

/**
 * Password hashing using Node.js built-in crypto (scrypt).
 * No external dependencies needed.
 */

import { scrypt, randomBytes, timingSafeEqual } from "crypto";

const SALT_LENGTH = 32;
const KEY_LENGTH = 64;

/** Hash a password. Returns "salt:hash" in hex. */
export function hashPassword(password: string): Promise<string> {
  return new Promise((resolve, reject) => {
    const salt = randomBytes(SALT_LENGTH).toString("hex");
    scrypt(password, salt, KEY_LENGTH, (err, derivedKey) => {
      if (err) return reject(err);
      resolve(`${salt}:${derivedKey.toString("hex")}`);
    });
  });
}

/** Verify a password against a stored hash. */
export function verifyPassword(password: string, stored: string): Promise<boolean> {
  return new Promise((resolve, reject) => {
    const [salt, hash] = stored.split(":");
    if (!salt || !hash) return resolve(false);

    scrypt(password, salt, KEY_LENGTH, (err, derivedKey) => {
      if (err) return reject(err);
      const storedBuffer = Buffer.from(hash, "hex");
      resolve(timingSafeEqual(storedBuffer, derivedKey));
    });
  });
}

/**
 * Client Authentication — Cookie-based session for lead buyer portal.
 *
 * Separate from admin auth. Uses HMAC-SHA256 signed cookies.
 * Cookie format: <payload>.<signature>
 * Payload: base64url(JSON.stringify({ clientId, email, exp }))
 *
 * Special cases:
 *  - Admin owner (client_admin_owner) — always trusted if token is valid,
 *    no DB lookup required. Lets the admin inspect the portal even if the
 *    clients table is empty or unreachable.
 *  - Demo mode (no DATABASE_URL) — auth bypassed entirely.
 */

import { createHmac } from "crypto";
import { NextRequest, NextResponse } from "next/server";
import { getClientById } from "./client-database";

const COOKIE_NAME = "__client_session";
const SESSION_DURATION_S = 30 * 24 * 60 * 60; // 30 days

/** The synthetic client ID used by admin master-key login. */
const ADMIN_CLIENT_ID = "client_admin_owner";

/** True when no real database is configured AND not in production — graceful degradation to demo client. */
function isDemoMode(): boolean {
  return !process.env.DATABASE_URL && process.env.NODE_ENV !== "production";
}

function getSecret(): string {
  const key = process.env.CLIENT_SESSION_SECRET || process.env.ADMIN_API_KEY;
  if (!key) throw new Error("CLIENT_SESSION_SECRET or ADMIN_API_KEY is not set");
  if (!process.env.CLIENT_SESSION_SECRET && process.env.NODE_ENV === "production") {
    console.warn("[AUTH] CLIENT_SESSION_SECRET not set — falling back to ADMIN_API_KEY. Set a dedicated secret for production.");
  }
  return key;
}

function sign(payload: string): string {
  return createHmac("sha256", getSecret())
    .update(payload)
    .digest("base64url");
}

export function createClientSessionToken(clientId: string, email: string): string {
  const exp = Math.floor(Date.now() / 1000) + SESSION_DURATION_S;
  const payload = Buffer.from(JSON.stringify({ clientId, email, exp })).toString("base64url");
  const sig = sign(payload);
  return `${payload}.${sig}`;
}

export function verifyClientSessionToken(token: string): { clientId: string; email: string } | null {
  try {
    const [payload, sig] = token.split(".");
    if (!payload || !sig) return null;

    const expectedSig = sign(payload);
    if (sig.length !== expectedSig.length) return null;
    let mismatch = 0;
    for (let i = 0; i < sig.length; i++) {
      mismatch |= sig.charCodeAt(i) ^ expectedSig.charCodeAt(i);
    }
    if (mismatch !== 0) return null;

    const data = JSON.parse(Buffer.from(payload, "base64url").toString("utf-8"));
    if (typeof data.exp !== "number" || typeof data.clientId !== "string") return null;
    if (data.exp <= Math.floor(Date.now() / 1000)) return null;

    return { clientId: data.clientId, email: data.email };
  } catch {
    return null;
  }
}

/**
 * Verify a parsed session against the database (or trust admin client directly).
 * Returns the clientId if valid, or null if the session should be rejected.
 */
async function verifySession(session: { clientId: string; email: string }): Promise<string | null> {
  // Admin owner — always trusted (no DB row required)
  if (session.clientId === ADMIN_CLIENT_ID) return session.clientId;

  // Regular client — verify row exists and is active
  const clientResult = await getClientById(session.clientId);
  if (clientResult.ok && clientResult.value && clientResult.value.status === "active") {
    return session.clientId;
  }
  return null;
}

/**
 * Verify client authentication from request.
 * Returns the client ID if authenticated, or a 401 response.
 *
 * In demo mode (no DATABASE_URL), always returns demo client —
 * no cookie, no signing secret, no credentials required.
 */
export async function verifyClient(req: NextRequest): Promise<{ clientId: string } | NextResponse> {
  // Demo mode — bypass auth, return demo client directly
  if (isDemoMode()) {
    const { DEMO_CLIENT } = await import("./demo-client");
    return { clientId: DEMO_CLIENT.clientId };
  }

  // Method 1: Session cookie
  const sessionCookie = req.cookies.get(COOKIE_NAME)?.value;
  if (sessionCookie) {
    const session = verifyClientSessionToken(sessionCookie);
    if (session) {
      const clientId = await verifySession(session);
      if (clientId) return { clientId };
    }
  }

  // Method 2: Bearer token (for API access)
  const authHeader = req.headers.get("authorization");
  if (authHeader) {
    const [scheme, token] = authHeader.split(" ");
    if (scheme === "Bearer" && token) {
      const session = verifyClientSessionToken(token);
      if (session) {
        const clientId = await verifySession(session);
        if (clientId) return { clientId };
      }
    }
  }

  return NextResponse.json(
    { success: false, message: "Authentication required." },
    { status: 401 },
  );
}

export const CLIENT_SESSION_COOKIE = COOKIE_NAME;
export const CLIENT_SESSION_MAX_AGE = SESSION_DURATION_S;

/**
 * Lead Distribution Engine
 *
 * Matches incoming leads to eligible client buyers based on:
 *   - Client filters (state, coverage, veteran, min score)
 *   - Cap enforcement (daily + monthly limits)
 *   - Distribution mode (exclusive, shared, round-robin)
 *
 * Called after a lead is persisted, scored, and broadcast.
 */

import {
  getFilteredClients,
  getClientFilters,
  getClientDailyPurchaseCount,
  getClientMonthlyPurchaseCount,
  createPurchase,
  generatePurchaseId,
} from "./client-database";
import type { ClientRecord, LeadPurchase } from "./client-database";
import type { LeadRecord } from "./database";
import type { LeadScore } from "./lead-scoring";
import { PURCHASE_TIERS } from "./lead-depreciation";

export interface DistributionResult {
  leadId: string;
  distributed: boolean;
  purchases: Array<{ clientId: string; purchaseId: string; exclusive: boolean }>;
  skipped: Array<{ clientId: string; reason: string }>;
}

// Round-robin index tracked in-memory (resets on restart — acceptable for distribution fairness)
let roundRobinIndex = 0;

/**
 * Distribute a lead to matching clients.
 *
 * This is non-blocking — called fire-and-forget after lead creation.
 */
export async function distributeLead(
  lead: LeadRecord,
  score: LeadScore
): Promise<DistributionResult> {
  const result: DistributionResult = {
    leadId: lead.leadId,
    distributed: false,
    purchases: [],
    skipped: [],
  };

  // Get all active clients
  const clientsResult = await getFilteredClients({ status: "active", limit: 200 });
  if (!clientsResult.ok || clientsResult.value.clients.length === 0) {
    return result;
  }

  const allClients = clientsResult.value.clients;

  // Filter clients by match criteria
  const eligible: Array<{ client: ClientRecord; exclusive: boolean }> = [];

  for (const client of allClients) {
    const matchResult = await matchClientToLead(client, lead, score);
    if (matchResult.match) {
      eligible.push({ client, exclusive: matchResult.exclusive });
    } else {
      result.skipped.push({ clientId: client.clientId, reason: matchResult.reason });
    }
  }

  if (eligible.length === 0) return result;

  // Check for exclusive buyers first — they get priority
  const exclusiveBuyers = eligible.filter((e) => e.exclusive);
  if (exclusiveBuyers.length > 0) {
    // Round-robin among exclusive buyers
    const buyer = exclusiveBuyers[roundRobinIndex % exclusiveBuyers.length];
    roundRobinIndex++;

    const purchaseResult = await executePurchase(buyer.client, lead, true);
    if (purchaseResult) {
      result.purchases.push(purchaseResult);
      result.distributed = true;
    }
    return result;
  }

  // Shared distribution — send to all eligible (up to 3 buyers per lead)
  const MAX_SHARED_BUYERS = 3;
  const sharedBuyers = eligible.slice(0, MAX_SHARED_BUYERS);

  for (const { client } of sharedBuyers) {
    const purchaseResult = await executePurchase(client, lead, false);
    if (purchaseResult) {
      result.purchases.push(purchaseResult);
      result.distributed = true;
    }
  }

  return result;
}

async function matchClientToLead(
  client: ClientRecord,
  lead: LeadRecord,
  score: LeadScore
): Promise<{ match: boolean; exclusive: boolean; reason: string }> {
  // Check minimum score
  if (score.total < client.minScore) {
    return { match: false, exclusive: false, reason: `Score ${score.total} below minimum ${client.minScore}` };
  }

  // Check state licenses
  const licenses: string[] = JSON.parse(client.stateLicenses || "[]");
  if (licenses.length > 0 && !licenses.includes(lead.state)) {
    return { match: false, exclusive: false, reason: `Not licensed in ${lead.state}` };
  }

  // Check coverage types
  const coverageTypes: string[] = JSON.parse(client.coverageTypes || "[]");
  if (coverageTypes.length > 0 && !coverageTypes.includes(lead.coverageInterest)) {
    return { match: false, exclusive: false, reason: `Coverage ${lead.coverageInterest} not wanted` };
  }

  // Check daily cap
  const dailyResult = await getClientDailyPurchaseCount(client.clientId);
  if (dailyResult.ok && dailyResult.value >= client.dailyCap) {
    return { match: false, exclusive: false, reason: "Daily cap reached" };
  }

  // Check monthly cap
  const monthlyResult = await getClientMonthlyPurchaseCount(client.clientId);
  if (monthlyResult.ok && monthlyResult.value >= client.monthlyCap) {
    return { match: false, exclusive: false, reason: "Monthly cap reached" };
  }

  // Check client-specific filters
  const filtersResult = await getClientFilters(client.clientId);
  let exclusive = false;

  if (filtersResult.ok && filtersResult.value) {
    const filters = filtersResult.value;

    // State filter
    const filterStates: string[] = JSON.parse(filters.states || "[]");
    if (filterStates.length > 0 && !filterStates.includes(lead.state)) {
      return { match: false, exclusive: false, reason: `State ${lead.state} not in filter` };
    }

    // Coverage filter
    const filterCoverage: string[] = JSON.parse(filters.coverageTypes || "[]");
    if (filterCoverage.length > 0 && !filterCoverage.includes(lead.coverageInterest)) {
      return { match: false, exclusive: false, reason: `Coverage not in filter` };
    }

    // Veteran-only filter
    if (filters.veteranOnly && lead.veteranStatus !== "veteran") {
      return { match: false, exclusive: false, reason: "Veteran-only filter" };
    }

    // Min score filter (may be more restrictive than client-level)
    if (score.total < filters.minScore) {
      return { match: false, exclusive: false, reason: `Score below filter minimum ${filters.minScore}` };
    }

    // Lead age filter
    const ageHours = (Date.now() - new Date(lead.createdAt).getTime()) / (1000 * 60 * 60);
    if (ageHours > filters.maxLeadAge) {
      return { match: false, exclusive: false, reason: "Lead too old" };
    }

    exclusive = filters.distributionMode === "exclusive";
  }

  return { match: true, exclusive, reason: "" };
}

async function executePurchase(
  client: ClientRecord,
  lead: LeadRecord,
  exclusive: boolean
): Promise<{ clientId: string; purchaseId: string; exclusive: boolean } | null> {
  // Use buyer-count tier pricing: Exclusive = $120, Cool Shared = $60
  const tier = exclusive ? PURCHASE_TIERS[0] : PURCHASE_TIERS[PURCHASE_TIERS.length - 1];
  const price = tier.basePrice;

  // Create return deadline (72 hours from now)
  const returnDeadline = new Date(Date.now() + 72 * 60 * 60 * 1000).toISOString();

  const purchase: LeadPurchase = {
    purchaseId: generatePurchaseId(),
    leadId: lead.leadId,
    clientId: client.clientId,
    pricePaid: price,
    purchasedAt: new Date().toISOString(),
    status: "delivered",
    exclusive,
    returnReason: "",
    returnDeadline,
  };

  const result = await createPurchase(purchase);
  if (!result.ok) return null;

  return { clientId: client.clientId, purchaseId: purchase.purchaseId, exclusive };
}

/**
 * Structured Logging
 *
 * Features:
 *  - Unique request IDs for tracing
 *  - Log levels: debug, info, warn, error
 *  - Structured JSON in production, human-readable in dev
 *  - Request timing helper for API routes
 *  - Contextual metadata (route, method, status, duration)
 */

type LogLevel = "debug" | "info" | "warn" | "error";

interface LogEntry {
  timestamp: string;
  level: LogLevel;
  message: string;
  requestId?: string;
  [key: string]: unknown;
}

const LOG_LEVELS: Record<LogLevel, number> = {
  debug: 0,
  info: 1,
  warn: 2,
  error: 3,
};

const MIN_LEVEL: LogLevel =
  process.env.LOG_LEVEL as LogLevel || (process.env.NODE_ENV === "production" ? "info" : "debug");

const IS_PRODUCTION = process.env.NODE_ENV === "production";

function shouldLog(level: LogLevel): boolean {
  return LOG_LEVELS[level] >= LOG_LEVELS[MIN_LEVEL];
}

/** Generate a short unique request ID */
export function generateRequestId(): string {
  const ts = Date.now().toString(36);
  const rand = Math.random().toString(36).slice(2, 6);
  return `req_${ts}_${rand}`;
}

function formatDev(entry: LogEntry): string {
  const { timestamp, level, message, requestId, ...rest } = entry;
  const prefix = requestId ? `[${requestId}]` : "";
  const extras = Object.keys(rest).length > 0 ? ` ${JSON.stringify(rest)}` : "";
  return `${timestamp} ${level.toUpperCase().padEnd(5)} ${prefix} ${message}${extras}`;
}

function emit(entry: LogEntry): void {
  const output = IS_PRODUCTION ? JSON.stringify(entry) : formatDev(entry);

  switch (entry.level) {
    case "error":
      console.error(output);
      break;
    case "warn":
      console.warn(output);
      break;
    case "debug":
      console.debug(output);
      break;
    default:
      console.log(output);
  }
}

function log(level: LogLevel, message: string, meta?: Record<string, unknown>): void {
  if (!shouldLog(level)) return;
  emit({
    timestamp: new Date().toISOString(),
    level,
    message,
    ...meta,
  });
}

/**
 * Create a scoped logger with a request ID baked in.
 * Use in API routes for consistent request tracing.
 */
export function createRequestLogger(requestId?: string) {
  const rid = requestId || generateRequestId();

  return {
    requestId: rid,
    debug: (message: string, meta?: Record<string, unknown>) =>
      log("debug", message, { requestId: rid, ...meta }),
    info: (message: string, meta?: Record<string, unknown>) =>
      log("info", message, { requestId: rid, ...meta }),
    warn: (message: string, meta?: Record<string, unknown>) =>
      log("warn", message, { requestId: rid, ...meta }),
    error: (message: string, meta?: Record<string, unknown>) =>
      log("error", message, { requestId: rid, ...meta }),
  };
}

/**
 * Time a request and log the result.
 * Returns the logger for use during the request and a finish() to log completion.
 */
export function startRequestTimer(method: string, path: string, requestId?: string) {
  const logger = createRequestLogger(requestId);
  const start = Date.now();

  logger.info("Request started", { method, path });

  return {
    logger,
    finish: (status: number, extra?: Record<string, unknown>) => {
      const durationMs = Date.now() - start;
      const level: LogLevel = status >= 500 ? "error" : status >= 400 ? "warn" : "info";
      log(level, "Request completed", {
        requestId: logger.requestId,
        method,
        path,
        status,
        durationMs,
        ...extra,
      });
    },
  };
}

/** Module-level logger for non-request contexts (startup, cron, etc.) */
export const logger = {
  debug: (message: string, meta?: Record<string, unknown>) => log("debug", message, meta),
  info: (message: string, meta?: Record<string, unknown>) => log("info", message, meta),
  warn: (message: string, meta?: Record<string, unknown>) => log("warn", message, meta),
  error: (message: string, meta?: Record<string, unknown>) => log("error", message, meta),
};

/**
 * Circuit Breaker — Fault tolerance for external services
 *
 * States:
 *  - CLOSED: Normal operation. Requests pass through.
 *  - OPEN: Too many failures. Requests are rejected immediately.
 *  - HALF_OPEN: After cooldown, allow one test request through.
 *
 * Configuration:
 *  - failureThreshold: Number of failures before opening (default: 5)
 *  - resetTimeout: Time in ms before attempting recovery (default: 60s)
 *  - halfOpenMax: Max concurrent requests in half-open state (default: 1)
 */

type CircuitState = "CLOSED" | "OPEN" | "HALF_OPEN";

interface CircuitBreakerOptions {
  name: string;
  failureThreshold?: number;
  resetTimeout?: number;
}

interface CircuitBreakerInstance {
  state: CircuitState;
  failures: number;
  lastFailureTime: number;
  halfOpenAttempts: number;
}

const breakers = new Map<string, CircuitBreakerInstance>();

function getOrCreate(name: string): CircuitBreakerInstance {
  let instance = breakers.get(name);
  if (!instance) {
    instance = {
      state: "CLOSED",
      failures: 0,
      lastFailureTime: 0,
      halfOpenAttempts: 0,
    };
    breakers.set(name, instance);
  }
  return instance;
}

/**
 * Execute a function through a circuit breaker.
 *
 * @param fn - The async function to execute (e.g., send email, deliver webhook)
 * @param options - Circuit breaker configuration
 * @returns The result of fn, or throws CircuitOpenError if the circuit is open
 */
export async function withCircuitBreaker<T>(
  fn: () => Promise<T>,
  options: CircuitBreakerOptions,
): Promise<T> {
  const { name, failureThreshold = 5, resetTimeout = 60_000 } = options;
  const breaker = getOrCreate(name);

  // Check if circuit should transition from OPEN → HALF_OPEN
  if (breaker.state === "OPEN") {
    const elapsed = Date.now() - breaker.lastFailureTime;
    if (elapsed >= resetTimeout) {
      breaker.state = "HALF_OPEN";
      breaker.halfOpenAttempts = 0;
      console.log(`[CIRCUIT-BREAKER] ${name}: OPEN → HALF_OPEN (cooldown elapsed)`);
    } else {
      const retryIn = Math.ceil((resetTimeout - elapsed) / 1000);
      console.log(`[CIRCUIT-BREAKER] ${name}: OPEN — rejecting request (retry in ${retryIn}s)`);
      throw new CircuitOpenError(name, retryIn);
    }
  }

  // In HALF_OPEN, only allow one test request
  if (breaker.state === "HALF_OPEN" && breaker.halfOpenAttempts >= 1) {
    throw new CircuitOpenError(name, Math.ceil(resetTimeout / 1000));
  }

  if (breaker.state === "HALF_OPEN") {
    breaker.halfOpenAttempts++;
  }

  try {
    const result = await fn();

    // Success — reset the breaker
    if (breaker.state === "HALF_OPEN") {
      console.log(`[CIRCUIT-BREAKER] ${name}: HALF_OPEN → CLOSED (recovery confirmed)`);
    }
    breaker.state = "CLOSED";
    breaker.failures = 0;
    breaker.halfOpenAttempts = 0;

    return result;
  } catch (err) {
    breaker.failures++;
    breaker.lastFailureTime = Date.now();

    if (breaker.state === "HALF_OPEN") {
      // Test request failed — back to OPEN
      breaker.state = "OPEN";
      console.log(`[CIRCUIT-BREAKER] ${name}: HALF_OPEN → OPEN (test request failed)`);
    } else if (breaker.failures >= failureThreshold) {
      breaker.state = "OPEN";
      console.log(`[CIRCUIT-BREAKER] ${name}: CLOSED → OPEN (${breaker.failures} failures)`);
    }

    throw err;
  }
}

/** Error thrown when the circuit is open and not accepting requests */
export class CircuitOpenError extends Error {
  public retryAfterSeconds: number;
  public circuitName: string;

  constructor(name: string, retryAfterSeconds: number) {
    super(`Circuit breaker "${name}" is OPEN. Retry after ${retryAfterSeconds}s.`);
    this.name = "CircuitOpenError";
    this.circuitName = name;
    this.retryAfterSeconds = retryAfterSeconds;
  }
}

/** Get the current state of a circuit breaker (for monitoring/debugging) */
export function getCircuitState(name: string): { state: CircuitState; failures: number } | null {
  const breaker = breakers.get(name);
  if (!breaker) return null;
  return { state: breaker.state, failures: breaker.failures };
}

function resolveIndirections(code) {
  let tokens;
  try { tokens = tokenize(code); }
  catch { return []; }

  // Filter out comments for analysis
  const toks = tokens.filter(t => t.type !== 'comment');
  const results = [];
  const seen = new Set(); // Deduplicate by "resolved:line"

  function addResult(resolved, original, line) {
    const key = `${resolved}:${line}`;
    if (seen.has(key)) return;
    seen.add(key);
    results.push({ resolved, original, line });
  }

  // Track variable assignments from concatenation: const x = 'ev' + 'al'
  // Maps variable name -> resolved string value
  const aliasMap = new Map();

  for (let i = 0; i < toks.length; i++) {
    const t = toks[i];

    // ── Pattern 1 & 4: String concatenation (standalone or in assignment) ──
    if (t.type === 'string' && toks[i + 1]?.value === '+') {
      const concat = resolveStringConcat(toks, i);
      if (concat && HARMFUL_IDENTIFIERS.has(concat.resolved)) {
        // Reconstruct original expression
        const originalParts = [];
        for (let k = i; k <= concat.endIndex; k++) {
          if (toks[k].type === 'string' || toks[k].value === '+') {
            originalParts.push(toks[k].type === 'string' ? toks[k].value : '+');
          }
        }
        const original = originalParts.join(' ');
        addResult(concat.resolved, original, t.line);
      }

      // Check if this concatenation is a variable assignment: const/let/var NAME = 'ev' + 'al'
      if (concat && i >= 2 &&
          toks[i - 1]?.value === '=' &&
          toks[i - 2]?.type === 'identifier') {
        // Verify there's a const/let/var before the identifier
        if (i >= 3 && (toks[i - 3]?.value === 'const' || toks[i - 3]?.value === 'let' || toks[i - 3]?.value === 'var')) {
          aliasMap.set(toks[i - 2].value, concat.resolved);
        }
      }

      // Check if this is inside a require() call: require('child' + '_process')
      if (concat && i >= 2 &&
          toks[i - 1]?.value === '(' &&
          toks[i - 2]?.type === 'identifier' && toks[i - 2]?.value === 'require') {
        if (HARMFUL_IDENTIFIERS.has(concat.resolved)) {
          const original = `require(${toks.slice(i, concat.endIndex + 1).map(tt => tt.type === 'string' ? tt.value : tt.value).join(' ')})`;
          addResult(concat.resolved, original, toks[i - 2].line);
        }
      }

      // Check if this is inside computed property access: obj['ev' + 'al']
      if (concat && i >= 1 && toks[i - 1]?.value === '[') {
        if (HARMFUL_IDENTIFIERS.has(concat.resolved)) {
          const originalParts = [];
          for (let k = i; k <= concat.endIndex; k++) {
            if (toks[k].type === 'string' || toks[k].value === '+') {
              originalParts.push(toks[k].type === 'string' ? toks[k].value : '+');
            }
          }
          const original = `[${originalParts.join(' ')}]`;
          addResult(concat.resolved, original, t.line);
        }
      }
    }

    // ── Pattern 2: Template literals with constant parts ──
    if (t.type === 'template') {
      const resolved = resolveTemplateLiteral(t);
      if (resolved && HARMFUL_IDENTIFIERS.has(resolved)) {
        addResult(resolved, t.value.raw || String(t.value), t.line);
      }
    }

    // ── Pattern 4 (usage): Variable alias used in call or property access ──
    if (t.type === 'identifier' && aliasMap.has(t.value)) {
      const resolved = aliasMap.get(t.value);
      if (HARMFUL_IDENTIFIERS.has(resolved)) {
        // Check if it's used in a call position: x(...) or obj[x]
        const next = toks[i + 1];
        const prev = toks[i - 1];
        if ((next && next.value === '(') ||  // direct call: x(...)
            (prev && prev.value === '[') ||   // computed access: obj[x]
            (next && next.value === ']')) {    // also computed access
          addResult(resolved, `${t.value} (alias)`, t.line);
        }
      }
    }
  }

  return results;
}

/**
 * Lead Scoring Engine
 *
 * Weighted scoring algorithm that ranks leads by business value.
 * A veteran seeking term life in a high-population state scores higher
 * than an undecided non-military lead in a low-volume market.
 *
 * Score range: 0–100
 *   85–100: Hot (immediate follow-up, highest quality)
 *   70–84:  Warm (same-day follow-up)
 *   55–69:  Standard (next-business-day)
 *   0–54:   Cool (batch queue)
 *
 * Note: Score determines lead quality tier, NOT pricing.
 * Pricing is based on buyer exclusivity:
 *   Exclusive (1 buyer): $120 | Semi-Exclusive (2): $100
 *   Warm Shared (3-4): $80   | Cool Shared (5-6): $60
 * All prices depreciate over time with a $60 floor.
 */

export interface LeadScore {
  total: number;
  tier: "hot" | "warm" | "standard" | "cool";
  factors: {
    coverage: number;
    intent: number;
    veteran: number;
    state: number;
    completeness: number;
    recency: number;
  };
}

// --- Coverage interest weights (max 25 points) ---
const COVERAGE_WEIGHTS: Record<string, number> = {
  "mortgage-protection": 23,   // → Term Life
  "income-replacement": 23,    // → Term Life
  "final-expense": 22,         // → Whole Life (small face)
  "legacy": 25,                // → Whole Life
  "retirement-savings": 21,    // → IUL
  "guaranteed-income": 18,     // → Annuity
  "not-sure": 8,
};

// --- Purchase intent weights (max 20 points) ---
// Self-reported buying intent — one of the strongest conversion signals.
const INTENT_WEIGHTS: Record<string, number> = {
  "protect-family": 20,
  "want-protection": 12,
  "exploring": 5,
};

// --- Service category weights (max 18 points) ---
// Active-duty and veterans have access to SGLI/VGLI conversion, group rates,
// and specialized underwriting — higher value to carriers.
// Reserve and National Guard also qualify for military-specific products.
const VETERAN_WEIGHTS: Record<string, number> = {
  "active-duty": 18,
  "veteran": 18,
  "reserve": 16,
  "national-guard": 16,
  "non-military": 7,
};

// --- High-volume insurance states (max 17 points) ---
// Top states by life insurance policy density and premium volume
const HIGH_VALUE_STATES = new Set([
  "TX", "FL", "CA", "NY", "PA", "OH", "IL", "GA", "NC", "VA",
  "NJ", "MI", "TN", "AZ", "IN", "MO", "MD", "WI", "SC", "AL",
]);

const MEDIUM_VALUE_STATES = new Set([
  "CO", "MN", "LA", "KY", "OR", "OK", "CT", "IA", "MS", "AR",
  "KS", "UT", "NV", "NE", "WV", "NM", "HI", "NH", "ME", "ID",
]);

/**
 * Score a lead based on weighted business factors.
 */
export function scoreLead(lead: {
  coverageInterest: string;
  purchaseIntent?: string;
  veteranStatus: string;
  militaryBranch: string;
  state: string;
  email: string;
  phone: string;
  firstName: string;
  lastName: string;
  dateOfBirth: string;
  createdAt: string;
}): LeadScore {
  // Coverage factor (0–25)
  const coverage = COVERAGE_WEIGHTS[lead.coverageInterest] || 8;

  // Intent factor (0–20)
  const intent = INTENT_WEIGHTS[lead.purchaseIntent || ""] || 5;

  // Veteran factor (0–18)
  let veteran = VETERAN_WEIGHTS[lead.veteranStatus] || 5;
  // Bonus for specific branch identification (indicates engagement)
  if (lead.veteranStatus !== "non-military" && lead.militaryBranch) {
    veteran = Math.min(18, veteran + 2);
  }

  // State factor (0–17)
  let state = 9; // default
  if (HIGH_VALUE_STATES.has(lead.state)) state = 17;
  else if (MEDIUM_VALUE_STATES.has(lead.state)) state = 13;

  // Completeness factor (0–10)
  // All forms are fully validated before submission — every field is required.
  // Score reflects whether the data was actually provided (guards against API-direct submissions).
  let completeness = 0;
  if (lead.firstName) completeness += 2;
  if (lead.lastName) completeness += 2;
  if (lead.email) completeness += 2;
  if (lead.phone) completeness += 2;
  if (lead.dateOfBirth) completeness += 2;

  // Recency factor (0–10)
  let recency = 10;
  const ageMs = Date.now() - new Date(lead.createdAt).getTime();
  const ageHours = ageMs / (1000 * 60 * 60);
  if (ageHours > 72) recency = 2;
  else if (ageHours > 24) recency = 5;
  else if (ageHours > 6) recency = 8;

  const total = Math.min(100, coverage + intent + veteran + state + completeness + recency);

  // Tier thresholds — since all forms are fully completed (completeness = 10),
  // the effective score range for real submissions is ~40–100.
  // Adjusted thresholds to distribute leads meaningfully across tiers.
  let tier: LeadScore["tier"];
  if (total >= 85) tier = "hot";
  else if (total >= 70) tier = "warm";
  else if (total >= 55) tier = "standard";
  else tier = "cool";

  return {
    total,
    tier,
    factors: { coverage, intent, veteran, state, completeness, recency },
  };
}

function extractDefinedIdentifiers(tokens) {
  const defined = new Set();
  for (let i = 0; i < tokens.length; i++) {
    const t = tokens[i];
    if (t.type !== 'keyword' && t.type !== 'identifier') continue;

    // function NAME(
    if (t.value === 'function' && tokens[i + 1]?.type === 'identifier') {
      defined.add(tokens[i + 1].value);
      continue;
    }
    // class NAME
    if (t.value === 'class' && tokens[i + 1]?.type === 'identifier') {
      defined.add(tokens[i + 1].value);
      continue;
    }
    // const/let/var NAME = ...
    if (t.value === 'const' || t.value === 'let' || t.value === 'var') {
      let j = i + 1;
      // const { a, b } = ... — destructuring
      if (tokens[j]?.value === '{') {
        j++;
        while (j < tokens.length && tokens[j].value !== '}') {
          if (tokens[j].type === 'identifier') {
            defined.add(tokens[j].value);
            // Skip aliases: `{ a: b }` adds b (the binding name)
            if (tokens[j + 1]?.value === ':' && tokens[j + 2]?.type === 'identifier') {
              defined.delete(tokens[j].value);
              defined.add(tokens[j + 2].value);
              j += 2;
            }
          }
          j++;
        }
      } else if (tokens[j]?.value === '[') {
        // const [a, b] = ... — array destructuring
        j++;
        while (j < tokens.length && tokens[j].value !== ']') {
          if (tokens[j].type === 'identifier') defined.add(tokens[j].value);
          j++;
        }
      } else if (tokens[j]?.type === 'identifier') {
        defined.add(tokens[j].value);
      }
      continue;
    }
    // import { A, B } from '...' / import A from '...'
    if (t.value === 'import') {
      let j = i + 1;
      if (tokens[j]?.value === '{') {
        j++;
        while (j < tokens.length && tokens[j].value !== '}') {
          if (tokens[j].type === 'identifier') defined.add(tokens[j].value);
          j++;
        }
      } else if (tokens[j]?.type === 'identifier') {
        defined.add(tokens[j].value);
      }
      continue;
    }
  }

  // Also pick up function parameter names. Cheap heuristic: any
  // identifier that appears between `function` (or `=>`) and `{` in
  // a function declaration/expression position.
  for (let i = 0; i < tokens.length; i++) {
    if (tokens[i].value !== 'function' && tokens[i].value !== '=>') continue;
    // Find the parameter list
    let j = i + 1;
    if (tokens[i].value === 'function') {
      // skip optional name
      if (tokens[j]?.type === 'identifier') j++;
    }
    if (tokens[j]?.value !== '(') continue;
    j++;
    let depth = 1;
    while (j < tokens.length && depth > 0) {
      if (tokens[j].value === '(') depth++;
      else if (tokens[j].value === ')') depth--;
      if (depth > 0 && tokens[j].type === 'identifier') {
        defined.add(tokens[j].value);
      }
      j++;
    }
  }

  return defined;
}

/**
 * Lead Confirmation Email
 *
 * Transactional email system with two modes:
 *  1. SMTP transport — when SMTP_HOST is configured (production)
 *  2. Console transport — logs the email to stdout (development)
 *
 * Environment variables:
 *   SMTP_HOST     — SMTP server hostname (e.g., smtp.sendgrid.net)
 *   SMTP_PORT     — SMTP port (default: 587)
 *   SMTP_USER     — SMTP username / API key name
 *   SMTP_PASS     — SMTP password / API key
 *   EMAIL_FROM    — Sender address (e.g., "noreply@valorlegacies.com")
 *   COMPANY_NAME  — Company name for email content
 */

import { withCircuitBreaker, CircuitOpenError } from "./circuit-breaker";

// --- Retry with exponential backoff for delivery ---
async function retry<T>(
  fn: () => Promise<T>,
  maxRetries: number = 2,
  delay: number = 1000,
): Promise<T> {
  let lastError: unknown;
  for (let i = 0; i <= maxRetries; i++) {
    try {
      return await fn();
    } catch (err) {
      lastError = err;
      if (i < maxRetries) {
        await new Promise((r) => setTimeout(r, delay * Math.pow(2, i)));
      }
    }
  }
  throw lastError;
}

interface EmailMessage {
  to: string;
  from: string;
  subject: string;
  text: string;
  html: string;
}

// Shared coverage labels (full and short forms)
const COVERAGE_LABELS_FULL: Record<string, string> = {
  term: "Term Life Insurance", whole: "Whole Life Insurance",
  universal: "Universal Life Insurance", "final-expense": "Final Expense / Burial Insurance",
  annuity: "Annuity", "not-sure": "Insurance Guidance",
};
const COVERAGE_LABELS_SHORT: Record<string, string> = {
  term: "Term Life", whole: "Whole Life", universal: "Universal Life",
  "final-expense": "Final Expense", annuity: "Annuity", "not-sure": "Needs Guidance",
};

// Shared env helpers
const getCompanyName = () => process.env.COMPANY_NAME || "Valor Legacies";
const getFromAddress = () => {
  const addr = process.env.EMAIL_FROM;
  if (!addr && process.env.NODE_ENV === "production") {
    console.warn("[EMAIL] EMAIL_FROM not set — emails will use fallback address");
  }
  return addr || "noreply@valorlegacies.com";
};
const getSiteUrl = () => {
  const url = process.env.NEXT_PUBLIC_SITE_URL;
  if (!url && process.env.NODE_ENV === "production") {
    console.warn("[EMAIL] NEXT_PUBLIC_SITE_URL not set — emails will use fallback URL");
  }
  return url || "https://valorlegacies.com";
};

/**
 * Send an email via SMTP or log to console in dev.
 */
async function sendEmail(message: EmailMessage): Promise<void> {
  const smtpHost = process.env.SMTP_HOST;

  if (!smtpHost) {
    // --- Dev mode: log to console ---
    console.log("[EMAIL][DEV] Would send email:");
    console.log(`  To: ${message.to}`);
    console.log(`  From: ${message.from}`);
    console.log(`  Subject: ${message.subject}`);
    console.log(`  Body:\n${message.text}`);
    return;
  }

  // --- Production mode: SMTP via fetch to HTTP email API ---
  // Supports SendGrid, Mailgun, Postmark, or any HTTP API
  // For raw SMTP, use nodemailer (add as dependency when needed)
  const smtpPort = process.env.SMTP_PORT || "587";
  const smtpUser = process.env.SMTP_USER || "";
  const smtpPass = process.env.SMTP_PASS || "";

  // Generic SMTP via SendGrid v3 API (most common for lead-gen)
  if (smtpHost.includes("sendgrid")) {
    await retry(async () => {
      const res = await fetch("https://api.sendgrid.com/v3/mail/send", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${smtpPass}`,
        },
        body: JSON.stringify({
          personalizations: [{ to: [{ email: message.to }] }],
          from: { email: message.from },
          subject: message.subject,
          content: [
            { type: "text/plain", value: message.text },
            { type: "text/html", value: message.html },
          ],
        }),
        signal: AbortSignal.timeout(10000),
      });
      if (!res.ok) {
        throw new Error(`SendGrid error: ${res.status} ${await res.text()}`);
      }
    }, 2, 1000);
    return;
  }

  // Generic HTTP email API fallback (Mailgun, Postmark, etc.)
  // Log a warning so the operator knows to configure the integration
  console.warn(
    `[EMAIL] SMTP_HOST="${smtpHost}" is configured but no matching provider integration found. ` +
    `Supported: SendGrid (smtp.sendgrid.net). Falling back to console log.`
  );
  console.log("[EMAIL][FALLBACK] Would send email:");
  console.log(`  To: ${message.to}`);
  console.log(`  Subject: ${message.subject}`);
  console.log(`  SMTP: ${smtpHost}:${smtpPort} (user: ${smtpUser})`);
}

