/**
 * Lead Notification Webhook System
 *
 * Webhooks are configured via environment variables:
 *   WEBHOOK_URLS — comma-separated list of endpoint URLs
 *   WEBHOOK_SECRET — shared secret for HMAC signature verification
 *
 * Each lead submission fires a POST to all configured endpoints with:
 *  - JSON payload of the lead data
 *  - X-Webhook-Signature header (HMAC-SHA256)
 *  - X-Webhook-Event header ("lead.created")
 *  - Retry with exponential backoff (3 attempts)
 */
import { createHmac } from "crypto";
import { withCircuitBreaker, CircuitOpenError } from "./circuit-breaker";

// --- Retry with exponential backoff ---
async function retry<T>(
  fn: () => Promise<T>,
  maxRetries: number = 3,
  delay: number = 1000,
): Promise<T> {
  let lastError: unknown;
  for (let i = 0; i <= maxRetries; i++) {
    try {
      return await fn();
    } catch (err) {
      lastError = err;
      if (i < maxRetries) {
        await new Promise((r) => setTimeout(r, delay * Math.pow(2, i)));
      }
    }
  }
  throw lastError;
}

// --- Result type for typed error handling ---
type Result<T, E = string> = { ok: true; value: T } | { ok: false; error: E };

export interface WebhookPayload {
  event: "lead.created";
  timestamp: string;
  data: {
    leadId: string;
    firstName: string;
    lastName: string;
    dateOfBirth: string;
    email: string;
    phone: string;
    state: string;
    coverageInterest: string;
    createdAt: string;
  };
}

interface WebhookResult {
  url: string;
  status: number;
  success: boolean;
}

/** Sign a payload with HMAC-SHA256 */
function signPayload(payload: string, secret: string): string {
  return createHmac("sha256", secret).update(payload).digest("hex");
}

/** Get configured webhook URLs from environment */
function getWebhookUrls(): string[] {
  const urls = process.env.WEBHOOK_URLS;
  if (!urls) return [];
  return urls
    .split(",")
    .map((u) => u.trim())
    .filter(Boolean);
}

/** Deliver a webhook to a single endpoint with retry */
async function deliverWebhook(
  url: string,
  payload: WebhookPayload,
  secret: string,
): Promise<Result<WebhookResult>> {
  const body = JSON.stringify(payload);
  const signature = secret ? signPayload(body, secret) : "";

  try {
    const response = await withCircuitBreaker(
      () => retry(
        async () => {
          const res = await fetch(url, {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
              "X-Webhook-Event": payload.event,
              "X-Webhook-Signature": signature ? `sha256=${signature}` : "",
              "X-Webhook-Timestamp": payload.timestamp,
            },
            body,
            signal: AbortSignal.timeout(10000),
          });

          if (!res.ok && res.status >= 500) {
            throw new Error(`Server error: ${res.status}`);
          }

          return res;
        },
        3,
        1000,
      ),
      // Per-URL circuit breaker: 3 failures → open for 2 minutes
      { name: `webhook-${new URL(url).hostname}`, failureThreshold: 3, resetTimeout: 120_000 },
    );

    return {
      ok: true,
      value: { url, status: response.status, success: response.ok },
    };
  } catch (err) {
    if (err instanceof CircuitOpenError) {
      console.warn(`[WEBHOOK CIRCUIT OPEN] ${url}: ${err.message}`);
      return { ok: false, error: `${url}: Circuit open — skipping` };
    }
    const message = err instanceof Error ? err.message : "Delivery failed";
    console.error(`[WEBHOOK FAILED] ${url}: ${message}`);
    return { ok: false, error: `${url}: ${message}` };
  }
}

/**
 * Fire webhooks for a new lead submission.
 * Non-blocking — errors are logged but don't affect the API response.
 */
export async function notifyLeadCreated(lead: {
  leadId: string;
  firstName: string;
  lastName: string;
  dateOfBirth: string;
  email: string;
  phone: string;
  state: string;
  coverageInterest: string;
  createdAt: string;
}): Promise<void> {
  const urls = getWebhookUrls();
  if (urls.length === 0) return;

  const secret = process.env.WEBHOOK_SECRET || "";

  const payload: WebhookPayload = {
    event: "lead.created",
    timestamp: new Date().toISOString(),
    data: {
      leadId: lead.leadId,
      firstName: lead.firstName,
      lastName: lead.lastName,
      dateOfBirth: lead.dateOfBirth,
      email: lead.email,
      phone: lead.phone,
      state: lead.state,
      coverageInterest: lead.coverageInterest,
      createdAt: lead.createdAt,
    },
  };

  // Fire all webhooks concurrently (non-blocking)
  const results = await Promise.allSettled(
    urls.map((url) => deliverWebhook(url, payload, secret)),
  );

  const successes = results.filter(
    (r) => r.status === "fulfilled" && r.value.ok,
  ).length;
  const failures = results.length - successes;

  if (failures > 0) {
    console.warn(
      `[WEBHOOKS] ${successes}/${results.length} delivered, ${failures} failed for lead ${lead.leadId}`,
    );
  } else {
    console.log(
      `[WEBHOOKS] ${successes}/${results.length} delivered for lead ${lead.leadId}`,
    );
  }
}

/**
 * Lightweight Sentry Error Reporter
 *
 * Uses Sentry's HTTP envelope API directly instead of the heavy @sentry/nextjs SDK.
 * Parses the DSN to extract the project ID, public key, and ingest URL,
 * then sends error events as envelopes via fetch.
 *
 * Environment variable:
 *  - NEXT_PUBLIC_SENTRY_DSN — Sentry DSN string (e.g. "https://key@o123.ingest.sentry.io/456")
 */

interface ParsedDsn {
  publicKey: string;
  host: string;
  projectId: string;
  envelopeUrl: string;
}

let parsedDsn: ParsedDsn | null = null;
let initialized = false;

/**
 * Parse a Sentry DSN into its component parts.
 *
 * DSN format: https://<public_key>@<host>/<project_id>
 * Envelope endpoint: https://<host>/api/<project_id>/envelope/
 */
function parseDsn(dsn: string): ParsedDsn | null {
  try {
    const url = new URL(dsn);
    const publicKey = url.username;
    const host = url.hostname + (url.port ? `:${url.port}` : "");
    const projectId = url.pathname.replace(/\//g, "");

    if (!publicKey || !projectId) return null;

    return {
      publicKey,
      host,
      projectId,
      envelopeUrl: `${url.protocol}//${host}/api/${projectId}/envelope/`,
    };
  } catch {
    return null;
  }
}

/**
 * Initialize Sentry. Call once at app startup.
 * Safe to call multiple times — subsequent calls are no-ops.
 */
export function initSentry(): void {
  if (initialized) return;
  initialized = true;

  const dsn = process.env.NEXT_PUBLIC_SENTRY_DSN;
  if (!dsn) return;

  parsedDsn = parseDsn(dsn);
  if (!parsedDsn) {
    console.warn("[Sentry] Invalid DSN, error reporting disabled.");
  }
}

/**
 * Build a Sentry envelope payload.
 * Envelope format: header\nitem_header\npayload
 * See: https://develop.sentry.dev/sdk/envelopes/
 */
function buildEnvelope(
  event: Record<string, unknown>,
  dsn: ParsedDsn,
): string {
  const envelopeHeader = JSON.stringify({
    event_id: crypto.randomUUID().replace(/-/g, ""),
    dsn: `https://${dsn.publicKey}@${dsn.host}/${dsn.projectId}`,
    sent_at: new Date().toISOString(),
  });

  const itemHeader = JSON.stringify({
    type: "event",
    content_type: "application/json",
  });

  const payload = JSON.stringify(event);

  return `${envelopeHeader}\n${itemHeader}\n${payload}`;
}

/**
 * Send an event envelope to Sentry.
 */
function sendEnvelope(event: Record<string, unknown>): void {
  if (!parsedDsn) return;

  const body = buildEnvelope(event, parsedDsn);

  // Use sendBeacon for reliability during page unload, fall back to fetch
  if (typeof navigator !== "undefined" && typeof navigator.sendBeacon === "function") {
    const sent = navigator.sendBeacon(parsedDsn.envelopeUrl, body);
    if (sent) return;
  }

  fetch(parsedDsn.envelopeUrl, {
    method: "POST",
    headers: { "Content-Type": "text/plain;charset=UTF-8" },
    body,
    keepalive: true,
  }).catch(() => {
    // Silently ignore — can't report an error about error reporting
  });
}

/**
 * Extract a clean error message and stack trace from an unknown error value.
 */
function normalizeError(error: unknown): { message: string; stack?: string } {
  if (error instanceof Error) {
    return {
      message: error.message,
      stack: error.stack,
    };
  }
  if (typeof error === "string") {
    return { message: error };
  }
  return { message: String(error) };
}

/**
 * Build a Sentry exception event from a stack trace string.
 */
function parseStackFrames(stack?: string): Array<Record<string, unknown>> {
  if (!stack) return [];

  const lines = stack.split("\n").slice(1); // Skip the error message line
  const frames: Array<Record<string, unknown>> = [];

  for (const line of lines) {
    const match = line.match(/at\s+(.+?)\s+\((.+?):(\d+):(\d+)\)/);
    if (match) {
      frames.push({
        function: match[1],
        filename: match[2],
        lineno: parseInt(match[3], 10),
        colno: parseInt(match[4], 10),
      });
      continue;
    }
    const simpleMatch = line.match(/at\s+(.+?):(\d+):(\d+)/);
    if (simpleMatch) {
      frames.push({
        filename: simpleMatch[1],
        lineno: parseInt(simpleMatch[2], 10),
        colno: parseInt(simpleMatch[3], 10),
      });
    }
  }

  return frames.reverse(); // Sentry expects frames in oldest-to-newest order
}

/**
 * Report an error to Sentry.
 *
 * @param error — The error to report (Error, string, or unknown)
 * @param context — Optional extra context to attach to the event
 */
export function captureException(
  error: unknown,
  context?: Record<string, unknown>,
): void {
  if (!parsedDsn) return;

  const { message, stack } = normalizeError(error);
  const frames = parseStackFrames(stack);

  const event: Record<string, unknown> = {
    platform: "javascript",
    level: "error",
    timestamp: Date.now() / 1000,
    environment: process.env.NODE_ENV || "production",
    request: typeof window !== "undefined" ? { url: window.location.href } : undefined,
    exception: {
      values: [
        {
          type: error instanceof Error ? error.constructor.name : "Error",
          value: message.slice(0, 1000),
          stacktrace: frames.length > 0 ? { frames } : undefined,
        },
      ],
    },
    extra: context,
  };

  sendEnvelope(event);
}

/**
 * Report a message to Sentry.
 *
 * @param message — The message text
 * @param level — Severity level (default: "info")
 */
export function captureMessage(
  message: string,
  level: "info" | "warning" | "error" = "info",
): void {
  if (!parsedDsn) return;

  const event: Record<string, unknown> = {
    platform: "javascript",
    level,
    timestamp: Date.now() / 1000,
    environment: process.env.NODE_ENV || "production",
    request: typeof window !== "undefined" ? { url: window.location.href } : undefined,
    message: {
      formatted: message.slice(0, 1000),
    },
  };

  sendEnvelope(event);
}

/**
 * A/B Testing Infrastructure
 *
 * Provides deterministic experiment variant assignment using cookies.
 * Variants are assigned via weighted random selection and persisted
 * in cookies for 30 days to ensure consistent user experience.
 *
 * Conversions are tracked through the analytics layer (analytics.ts).
 */

import { trackEvent } from "./analytics";

// ─── Types ───

export type Experiment = {
  id: string;
  variants: string[];
  weights?: number[];
};

// ─── Cookie Helpers ───

/**
 * Get the value of a cookie by name.
 * Returns null if not found or if running on the server.
 */
function getCookie(name: string): string | null {
  if (typeof document === "undefined") return null;
  const match = document.cookie.match(
    new RegExp("(?:^|;\\s*)" + name.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + "=([^;]*)"),
  );
  return match ? decodeURIComponent(match[1]) : null;
}

/**
 * Set a cookie with the given name, value, and expiry in days.
 */
function setCookie(name: string, value: string, days: number): void {
  if (typeof document === "undefined") return;
  const expires = new Date(Date.now() + days * 864e5).toUTCString();
  document.cookie = `${name}=${encodeURIComponent(value)}; expires=${expires}; path=/; SameSite=Lax`;
}

// ─── Variant Assignment ───

/**
 * Select a variant using weighted random assignment.
 *
 * @param variants - Array of variant names (e.g. ["control", "variant-a", "variant-b"])
 * @param weights  - Optional array of weights (must match variants length).
 *                   Defaults to equal weighting if omitted.
 * @returns The selected variant name.
 */
function weightedRandom(variants: string[], weights?: number[]): string {
  if (variants.length === 0) {
    throw new Error("[ab-testing] variants array must not be empty");
  }

  // Default to equal weights
  const w = weights && weights.length === variants.length
    ? weights
    : variants.map(() => 1 / variants.length);

  // Normalize weights to sum to 1
  const total = w.reduce((sum, v) => sum + v, 0);
  const normalized = w.map((v) => v / total);

  // Weighted random selection
  const rand = Math.random();
  let cumulative = 0;
  for (let i = 0; i < normalized.length; i++) {
    cumulative += normalized[i];
    if (rand < cumulative) {
      return variants[i];
    }
  }

  // Fallback — should only happen due to floating point rounding
  return variants[variants.length - 1];
}

/**
 * Get the assigned variant for an experiment.
 *
 * If the user already has a cookie for this experiment, returns the stored variant.
 * Otherwise, assigns a new variant using weighted random selection, stores it
 * in a cookie for 30 days, and returns it.
 *
 * @param experimentId - Unique experiment identifier (used as cookie suffix)
 * @param variants     - Array of variant names
 * @param weights      - Optional array of weights for each variant
 * @returns The assigned variant name
 */
export function getVariant(
  experimentId: string,
  variants: string[],
  weights?: number[],
): string {
  const cookieName = `ab_${experimentId}`;

  // Check for existing assignment
  const existing = getCookie(cookieName);
  if (existing && variants.includes(existing)) {
    return existing;
  }

  // Assign new variant
  const variant = weightedRandom(variants, weights);
  setCookie(cookieName, variant, 30);

  // Track the assignment event
  trackEvent({
    event: "experiment_assigned",
    category: "ab_test",
    label: experimentId,
    metadata: { variant },
  });

  return variant;
}

/**
 * Track a conversion event for an experiment.
 *
 * Fires an analytics event with the experiment ID and assigned variant,
 * allowing you to measure which variant drove the conversion.
 *
 * @param experimentId - The experiment that produced the conversion
 * @param variant      - The variant the user was assigned to
 */
export function trackExperimentConversion(
  experimentId: string,
  variant: string,
): void {
  trackEvent({
    event: "experiment_conversion",
    category: "ab_test",
    label: experimentId,
    value: 1,
    metadata: { variant },
  });
}

/**
 * Pricing Configuration — Admin-Adjustable Settings
 *
 * Stores and loads the pricing/depreciation configuration as JSON.
 * The admin portal can update these values at any time.
 *
 * Storage: JSON file at .data/pricing-config.json (persists across restarts)
 * Fallback: hardcoded defaults if file doesn't exist
 */

import { readFileSync, writeFileSync, mkdirSync, existsSync } from "fs";
import path from "path";

// =============================================================================
// Types
// =============================================================================

export interface TierConfig {
  name: string;
  maxBuyers: number;
  basePrice: number;    // cents
  holdDays: number;
  dropAmount: number;   // cents per step
  dropInterval: number; // days between each step
}

export interface PricingConfig {
  maxPrice: number;     // cents — absolute ceiling
  priceFloor: number;   // cents — absolute minimum
  tiers: TierConfig[];
  updatedAt: string;
  updatedBy: string;
}

// =============================================================================
// Defaults — used when no config file exists
// =============================================================================

export const DEFAULT_PRICING_CONFIG: PricingConfig = {
  maxPrice: 12000,    // $120.00
  priceFloor: 6000,   // $60.00
  tiers: [
    { name: "Exclusive",      maxBuyers: 1, basePrice: 12000, holdDays: 3, dropAmount: 500, dropInterval: 1 },
    { name: "Semi-Exclusive",  maxBuyers: 2, basePrice: 10000, holdDays: 2, dropAmount: 500, dropInterval: 1 },
    { name: "Warm Shared",    maxBuyers: 4, basePrice: 8000,  holdDays: 1, dropAmount: 300, dropInterval: 1 },
    { name: "Cool Shared",    maxBuyers: 6, basePrice: 6000,  holdDays: 0, dropAmount: 0,   dropInterval: 1 },
  ],
  updatedAt: new Date().toISOString(),
  updatedBy: "system",
};

// =============================================================================
// File path
// =============================================================================

const DATA_DIR = path.join(process.cwd(), ".data");
const CONFIG_FILE = path.join(DATA_DIR, "pricing-config.json");

// =============================================================================
// Read / Write
// =============================================================================

/** In-memory cache to avoid reading the file on every request. */
let _cache: PricingConfig | null = null;
let _cacheTime = 0;
const CACHE_TTL_MS = 5000; // 5 seconds

/**
 * Load the current pricing config. Returns cached version if fresh.
 */
export function getPricingConfig(): PricingConfig {
  const now = Date.now();
  if (_cache && now - _cacheTime < CACHE_TTL_MS) {
    return _cache;
  }

  try {
    if (existsSync(CONFIG_FILE)) {
      const raw = readFileSync(CONFIG_FILE, "utf-8");
      const parsed = JSON.parse(raw) as PricingConfig;
      // Validate structure minimally
      if (parsed.tiers && Array.isArray(parsed.tiers) && parsed.tiers.length > 0) {
        _cache = parsed;
        _cacheTime = now;
        return parsed;
      }
    }
  } catch {
    // Corrupted file — fall through to defaults
  }

  _cache = DEFAULT_PRICING_CONFIG;
  _cacheTime = now;
  return DEFAULT_PRICING_CONFIG;
}

/**
 * Save a new pricing config. Validates before writing.
 */
export function savePricingConfig(config: PricingConfig): { ok: true } | { ok: false; error: string } {
  // Validate
  if (!config.tiers || !Array.isArray(config.tiers) || config.tiers.length === 0) {
    return { ok: false, error: "At least one tier is required." };
  }

  if (config.maxPrice < 100) {
    return { ok: false, error: "Max price must be at least $1.00 (100 cents)." };
  }

  if (config.priceFloor < 0) {
    return { ok: false, error: "Price floor cannot be negative." };
  }

  if (config.priceFloor > config.maxPrice) {
    return { ok: false, error: "Price floor cannot exceed max price." };
  }

  for (const tier of config.tiers) {
    if (!tier.name || tier.name.trim().length === 0) {
      return { ok: false, error: "Every tier must have a name." };
    }
    if (tier.maxBuyers < 1) {
      return { ok: false, error: `Tier "${tier.name}": max buyers must be at least 1.` };
    }
    if (tier.basePrice < config.priceFloor) {
      return { ok: false, error: `Tier "${tier.name}": base price cannot be below the floor ($${(config.priceFloor / 100).toFixed(2)}).` };
    }
    if (tier.basePrice > config.maxPrice) {
      return { ok: false, error: `Tier "${tier.name}": base price cannot exceed max price ($${(config.maxPrice / 100).toFixed(2)}).` };
    }
    if (tier.dropAmount < 0) {
      return { ok: false, error: `Tier "${tier.name}": drop amount cannot be negative.` };
    }
    if (tier.dropInterval < 1) {
      return { ok: false, error: `Tier "${tier.name}": drop interval must be at least 1 day.` };
    }
  }

  try {
    if (!existsSync(DATA_DIR)) {
      mkdirSync(DATA_DIR, { recursive: true });
    }
    writeFileSync(CONFIG_FILE, JSON.stringify(config, null, 2), "utf-8");
    // Invalidate cache
    _cache = config;
    _cacheTime = Date.now();
    return { ok: true };
  } catch (err) {
    return { ok: false, error: `Failed to write config: ${err instanceof Error ? err.message : "unknown error"}` };
  }
}

