/**
 * POST /api/admin/agent-analytics
 *
 * Update AI agent settings.
 * Accepts: { llmsTxt, agentApiEnabled, consentExpiryHours, rateLimits, allowedAgents }
 */
export async function POST(req: NextRequest) {
  const authError = verifyAdmin(req);
  if (authError) return authError;

  let body: Record<string, unknown>;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json(
      { success: false, message: "Invalid JSON body." },
      { status: 400 },
    );
  }

  const current = await loadSettings();

  // Validate and merge
  if (typeof body.llmsTxt === "string") {
    current.llmsTxt = body.llmsTxt;
  }
  if (typeof body.agentApiEnabled === "boolean") {
    current.agentApiEnabled = body.agentApiEnabled;
  }
  if (typeof body.consentExpiryHours === "number" && body.consentExpiryHours > 0) {
    current.consentExpiryHours = body.consentExpiryHours;
  }
  if (body.rateLimits && typeof body.rateLimits === "object" && !Array.isArray(body.rateLimits)) {
    const rl = body.rateLimits as Record<string, unknown>;
    for (const [key, val] of Object.entries(rl)) {
      if (typeof val === "number" && val > 0) {
        current.rateLimits[key] = val;
      }
    }
  }
  if (Array.isArray(body.allowedAgents)) {
    current.allowedAgents = body.allowedAgents.filter(
      (a): a is string => typeof a === "string" && a.length > 0,
    );
  }

  await saveSettings(current);

  return NextResponse.json({
    success: true,
    message: "Agent settings updated.",
    settings: current,
  });
}

/**
 * Agent API Key Authentication
 *
 * AI agents authenticate via Bearer token in the Authorization header.
 * API keys are configured via AGENT_API_KEYS environment variable.
 *
 * Supports two formats (auto-detected per entry):
 *   Hashed (preferred):   "sha256hex:label"  (64-char hex before colon)
 *   Plaintext (compat):   "key:label"        (hashed at parse time)
 *
 * Generate hashed keys:
 *   node -e "console.log(require('crypto').createHash('sha256').update('my-key').digest('hex'))"
 */

import { NextRequest } from "next/server";
import { createHash, createHmac, randomBytes, timingSafeEqual } from "crypto";

export interface AgentIdentity {
  key: string;
  label: string;
}

/** SHA-256 hash a plaintext API key. */
export function hashApiKey(plaintext: string): string {
  return createHash("sha256").update(plaintext).digest("hex");
}

/**
 * Parse AGENT_API_KEYS env var into a map of sha256-hash → label.
 * Pre-hashed keys (64-char hex) are used as-is; plaintext keys are hashed on load.
 */
function getAgentKeys(): Map<string, string> {
  const raw = process.env.AGENT_API_KEYS || "";
  const keys = new Map<string, string>();

  for (const entry of raw.split(",")) {
    const trimmed = entry.trim();
    if (!trimmed) continue;

    const colonIdx = trimmed.indexOf(":");
    if (colonIdx > 0) {
      const keyPart = trimmed.slice(0, colonIdx);
      const label = trimmed.slice(colonIdx + 1);
      const isPreHashed = /^[0-9a-f]{64}$/.test(keyPart);
      keys.set(isPreHashed ? keyPart : hashApiKey(keyPart), label);
    } else {
      keys.set(hashApiKey(trimmed), "unknown-agent");
    }
  }

  return keys;
}

/**
 * Validate an agent API key from the request.
 * Hashes the incoming bearer token and compares against stored hashes
 * using timing-safe comparison to prevent timing attacks.
 */
export function authenticateAgent(req: NextRequest): AgentIdentity | null {
  const authHeader = req.headers.get("authorization");
  if (!authHeader) return null;

  const match = authHeader.match(/^Bearer\s+(.+)$/i);
  if (!match) return null;

  const key = match[1].trim();
  const incomingHash = hashApiKey(key);
  const incomingBuf = Buffer.from(incomingHash, "hex");

  const keys = getAgentKeys();

  for (const [storedHash, label] of keys) {
    const storedBuf = Buffer.from(storedHash, "hex");
    if (storedBuf.length === incomingBuf.length && timingSafeEqual(storedBuf, incomingBuf)) {
      return { key: storedHash, label };
    }
  }

  return null;
}

// --- Consent Token System ---

/**
 * Consent tokens are HMAC-signed payloads that prove a human approved
 * an AI agent's action. Format: base64url(payload).signature
 *
 * Payload: { email, scope, agentLabel, exp, confirmed }
 */

export interface ConsentPayload {
  email: string;
  scope: "lead-submission" | "account-registration" | "both";
  agentLabel: string;
  exp: number;
  confirmed: boolean;
  consentId: string;
}

const CONSENT_DURATION_S = 24 * 60 * 60; // 24 hours

function getConsentSecret(): string {
  const key = process.env.AGENT_CONSENT_SECRET || process.env.NEXTAUTH_SECRET || process.env.ADMIN_API_KEY;
  if (!key) throw new Error("AGENT_CONSENT_SECRET, NEXTAUTH_SECRET, or ADMIN_API_KEY must be set");
  if (!process.env.AGENT_CONSENT_SECRET && process.env.NODE_ENV === "production") {
    console.warn("[AUTH] AGENT_CONSENT_SECRET not set — using fallback secret. Set a dedicated secret for production.");
  }
  return key;
}

function signConsent(payload: string): string {
  return createHmac("sha256", getConsentSecret())
    .update(payload)
    .digest("base64url");
}

/** Create a pending (unconfirmed) consent token */
export function createConsentToken(
  email: string,
  scope: ConsentPayload["scope"],
  agentLabel: string,
): { token: string; consentId: string; expiresAt: string } {
  const consentId = `consent_${Date.now().toString(36)}_${randomBytes(6).toString("hex")}`;
  const exp = Math.floor(Date.now() / 1000) + CONSENT_DURATION_S;
  const payload: ConsentPayload = { email, scope, agentLabel, exp, confirmed: false, consentId };

  const encoded = Buffer.from(JSON.stringify(payload)).toString("base64url");
  const sig = signConsent(encoded);
  const token = `${encoded}.${sig}`;

  return {
    token,
    consentId,
    expiresAt: new Date(exp * 1000).toISOString(),
  };
}

/** Confirm a consent token (called when the human clicks the confirmation link) */
export function confirmConsentToken(token: string): { token: string; payload: ConsentPayload } | null {
  const decoded = verifyConsentToken(token);
  if (!decoded) return null;

  // Re-sign with confirmed=true
  const confirmed: ConsentPayload = { ...decoded, confirmed: true };
  const encoded = Buffer.from(JSON.stringify(confirmed)).toString("base64url");
  const sig = signConsent(encoded);

  return {
    token: `${encoded}.${sig}`,
    payload: confirmed,
  };
}

/** Verify and decode a consent token. Returns null if invalid or expired. */
export function verifyConsentToken(token: string): ConsentPayload | null {
  try {
    const [encoded, sig] = token.split(".");
    if (!encoded || !sig) return null;

    const expectedSig = signConsent(encoded);

    // Constant-time comparison
    if (sig.length !== expectedSig.length) return null;
    let mismatch = 0;
    for (let i = 0; i < sig.length; i++) {
      mismatch |= sig.charCodeAt(i) ^ expectedSig.charCodeAt(i);
    }
    if (mismatch !== 0) return null;

    const data = JSON.parse(Buffer.from(encoded, "base64url").toString("utf-8")) as ConsentPayload;

    if (typeof data.exp !== "number") return null;
    if (data.exp <= Math.floor(Date.now() / 1000)) return null;

    return data;
  } catch {
    return null;
  }
}

/**
 * Lead Price Depreciation Engine
 *
 * Reads pricing tiers and depreciation settings from admin-configurable storage.
 * All values are adjustable via the Admin Portal > Pricing page.
 *
 * Default pricing tiers (buyer exclusivity):
 *   - Exclusive   (1 buyer):    $120
 *   - Semi-exclusive (2 buyers): $100
 *   - Warm shared (3–4 buyers):  $80
 *   - Cool shared (5–6 buyers):  $60
 *
 * Time-based depreciation:
 *   P(t) = basePrice − dropAmount × max(0, ⌊(t − holdDays) / dropInterval⌋)
 *   P(t) = max(floor, P(t))
 */

import { getPricingConfig, type TierConfig, type PricingConfig } from "./pricing-config";

// Re-export types for convenience
export type { TierConfig, PricingConfig };

// =============================================================================
// Public interface (matches the shapes consumers expect)
// =============================================================================

export interface PurchaseTier {
  name: string;
  maxBuyers: number;
  basePrice: number;
}

export interface DepreciationConfig {
  maxPrice: number;
  holdDays: number;
  dropAmount: number;
  dropInterval: number;
  floor: number;
}

// =============================================================================
// Config accessors — always read from the admin-configurable store
// =============================================================================

/** Get all purchase tiers from the current config. */
export function getPurchaseTiers(): PurchaseTier[] {
  const config = getPricingConfig();
  return config.tiers.map((t) => ({
    name: t.name,
    maxBuyers: t.maxBuyers,
    basePrice: t.basePrice,
  }));
}

/** Convenience: PURCHASE_TIERS as a getter for backwards compatibility. */
export const PURCHASE_TIERS = new Proxy([] as PurchaseTier[], {
  get(_target, prop) {
    const tiers = getPurchaseTiers();
    if (prop === "length") return tiers.length;
    if (prop === Symbol.iterator) return tiers[Symbol.iterator].bind(tiers);
    if (prop === "map") return tiers.map.bind(tiers);
    if (prop === "find") return tiers.find.bind(tiers);
    if (prop === "filter") return tiers.filter.bind(tiers);
    if (prop === "every") return tiers.every.bind(tiers);
    if (prop === "forEach") return tiers.forEach.bind(tiers);
    if (typeof prop === "string" && !isNaN(Number(prop))) {
      return tiers[Number(prop)];
    }
    return (tiers as unknown as Record<string | symbol, unknown>)[prop];
  },
});

/** Get the max price ceiling from config. */
export function getMaxPrice(): number {
  return getPricingConfig().maxPrice;
}

/** Get the price floor from config. */
export function getPriceFloor(): number {
  return getPricingConfig().priceFloor;
}

/** Get a tier by its index (clamped to valid range). */
export function getTierByIndex(tierIndex: number): PurchaseTier {
  const tiers = getPurchaseTiers();
  const idx = Math.max(0, Math.min(tierIndex, tiers.length - 1));
  return tiers[idx];
}

/** Build a DepreciationConfig for a given tier name. */
function getDepreciationForTier(tierName: string): DepreciationConfig {
  const config = getPricingConfig();
  const tier = config.tiers.find((t) => t.name === tierName);
  if (tier) {
    return {
      maxPrice: tier.basePrice,
      holdDays: tier.holdDays,
      dropAmount: tier.dropAmount,
      dropInterval: tier.dropInterval,
      floor: config.priceFloor,
    };
  }
  // Fallback to last tier (cheapest)
  const fallback = config.tiers[config.tiers.length - 1];
  return {
    maxPrice: fallback.basePrice,
    holdDays: fallback.holdDays,
    dropAmount: fallback.dropAmount,
    dropInterval: fallback.dropInterval,
    floor: config.priceFloor,
  };
}

// =============================================================================
// Buyer-count status
// =============================================================================

/**
 * Determine buyer status for a lead based on active buyer count.
 */
export function getLeadBuyerStatus(activeBuyerCount: number): {
  currentTier: PurchaseTier;
  soldOut: boolean;
  availableTiers: Array<PurchaseTier & { soldOut: boolean }>;
} {
  const tiers = getPurchaseTiers();
  const availableTiers = tiers.map((tier) => ({
    ...tier,
    soldOut: activeBuyerCount >= tier.maxBuyers,
  }));

  const currentTier = tiers.find((t) => activeBuyerCount < t.maxBuyers)
    || tiers[tiers.length - 1];

  const soldOut = activeBuyerCount >= tiers[tiers.length - 1].maxBuyers;

  return { currentTier, soldOut, availableTiers };
}

// =============================================================================
// Depreciation calculation
// =============================================================================

/**
 * Calculate the depreciated price for a lead at a given age.
 */
export function calculateDepreciatedPrice(
  ageInDays: number,
  config: DepreciationConfig
): number {
  if (ageInDays <= config.holdDays) {
    return config.maxPrice;
  }
  const steps = Math.floor((ageInDays - config.holdDays) / config.dropInterval);
  const price = config.maxPrice - config.dropAmount * steps;
  return Math.max(config.floor, price);
}

/**
 * Get the current price for a specific purchase tier, factoring in lead age.
 */
export function getLeadPrice(
  createdAt: string,
  tierName: string,
): {
  price: number;
  ageInDays: number;
  isHolding: boolean;
  stepsDown: number;
  config: DepreciationConfig;
} {
  const config = getDepreciationForTier(tierName);
  const ageMs = Date.now() - new Date(createdAt).getTime();
  const ageInDays = Math.max(0, ageMs / (1000 * 60 * 60 * 24));

  const price = calculateDepreciatedPrice(ageInDays, config);
  const isHolding = ageInDays <= config.holdDays;
  const stepsDown = isHolding
    ? 0
    : Math.floor((ageInDays - config.holdDays) / config.dropInterval);

  return { price, ageInDays, isHolding, stepsDown, config };
}

/**
 * Get all tier prices for a lead at its current age.
 */
export function getAllTierPrices(
  createdAt: string,
  activeBuyerCount: number
): Array<{
  tier: PurchaseTier;
  price: number;
  soldOut: boolean;
  isHolding: boolean;
  stepsDown: number;
}> {
  const { availableTiers } = getLeadBuyerStatus(activeBuyerCount);

  return availableTiers.map((t) => {
    const { price, isHolding, stepsDown } = getLeadPrice(createdAt, t.name);
    return {
      tier: { name: t.name, maxBuyers: t.maxBuyers, basePrice: t.basePrice },
      price,
      soldOut: t.soldOut,
      isHolding,
      stepsDown,
    };
  });
}

/**
 * Conversion and Analytics Tracking
 *
 * Privacy-first analytics:
 *  - Checks cookie consent before firing any tracking events
 *  - Supports configurable conversion pixels via env vars
 *  - Tracks: page views, form step progress, conversions
 *  - Extensible: add Google Ads, Facebook Pixel, etc. via gtag/fbq globals
 *
 * No third-party scripts are loaded by default — this provides
 * the event dispatch layer. External pixels are fired only when
 * their global (gtag, fbq) is present on the window.
 */

/** Check if user has accepted analytics cookies (stored in localStorage by cookie-consent component) */
function hasAnalyticsConsent(): boolean {
  if (typeof window === "undefined") return false;
  try {
    const stored = localStorage.getItem("dc_cookie_consent");
    if (!stored) return false;
    const parsed = JSON.parse(stored);
    return parsed.choice === "accepted";
  } catch {
    return false;
  }
}

/* eslint-disable @typescript-eslint/no-explicit-any */
/** Safe access to window.gtag (Google Ads / GA4) */
function gtag(...args: unknown[]): void {
  if (typeof window !== "undefined") {
    const w = window as any;
    if (typeof w.gtag === "function") w.gtag(...args);
  }
}

/** Safe access to window.fbq (Meta/Facebook Pixel) */
function fbq(...args: unknown[]): void {
  if (typeof window !== "undefined") {
    const w = window as any;
    if (typeof w.fbq === "function") w.fbq(...args);
  }
}
/* eslint-enable @typescript-eslint/no-explicit-any */

export interface ConversionEvent {
  event: string;
  category?: string;
  label?: string;
  value?: number;
  metadata?: Record<string, string | number | boolean>;
}

/**
 * Track a custom analytics event.
 * Respects cookie consent — events are silently dropped if consent is not given.
 */
export function trackEvent(event: ConversionEvent): void {
  if (!hasAnalyticsConsent()) return;

  // Google Analytics / Google Ads
  gtag("event", event.event, {
    event_category: event.category,
    event_label: event.label,
    value: event.value,
    ...event.metadata,
  });

  // Facebook Pixel
  fbq("trackCustom", event.event, {
    category: event.category,
    label: event.label,
    value: event.value,
    ...event.metadata,
  });
}

/**
 * Track a lead form conversion.
 * Fires standard conversion events on all configured pixels.
 */
export function trackConversion(leadId: string, coverageType: string, state: string): void {
  if (!hasAnalyticsConsent()) return;

  // Google Ads conversion
  gtag("event", "conversion", {
    send_to: process.env.NEXT_PUBLIC_GOOGLE_ADS_CONVERSION_ID || "",
    event_category: "lead",
    event_label: coverageType,
    value: 1,
  });

  // Facebook Pixel Lead event
  fbq("track", "Lead", {
    content_name: coverageType,
    content_category: "life_insurance",
    status: "submitted",
  });

  // Generic event for any other analytics
  trackEvent({
    event: "lead_submitted",
    category: "conversion",
    label: coverageType,
    value: 1,
    metadata: { leadId, state },
  });
}

/**
 * Track form step progression.
 * Useful for funnel analysis — see where users drop off.
 */
export function trackFormStep(step: number, stepName: string): void {
  trackEvent({
    event: "form_step",
    category: "engagement",
    label: stepName,
    value: step,
  });
}

/**
 * Track page view (for SPA navigation).
 */
export function trackPageView(path: string, title?: string): void {
  if (!hasAnalyticsConsent()) return;

  gtag("event", "page_view", {
    page_path: path,
    page_title: title,
  });

  fbq("track", "PageView");
}

